window.KJV1769_STRONG_BOOKS["Zech"] = {"osis":"Zech","book":"스가랴","verses":{"1:1":{"text":"In the eighth month, in the second year of Darius, came the word of the LORD unto Zechariah, the son of Berechiah, the son of Iddo the prophet, saying,","words":[["H8066","In the eighth",0,13],["H2320","month",14,19],["H8147","in the second",21,34],["H8141","year",35,39],["H1867","of Darius",40,49],["H1697","came the word",51,64],["H3068","of the LORD",65,76],["H2148","unto Zechariah",77,91],["H1121","the son",93,100],["H1296","of Berechiah",101,113],["H1121","the son",115,122],["H5714","of Iddo",123,130],["H5030","the prophet",131,142],["H0559","saying",144,150]]},"1:2":{"text":"The LORD hath been sore displeased with your fathers.","words":[["H3068","The LORD",0,8],["H7110","hath been sore",9,23],["H7107","displeased",24,34],["H0001","with your fathers",35,52]]},"1:3":{"text":"Therefore say thou unto them, Thus saith the LORD of hosts; Turn ye unto me, saith the LORD of hosts, and I will turn unto you, saith the LORD of hosts.","words":[["H0559","Therefore say",0,13],["H0559","thou unto them, Thus saith",14,40],["H3068","the LORD",41,49],["H6635","of hosts",50,58],["H7725","Turn",60,64],["H5002","ye unto me, saith",65,82],["H3068","the LORD",83,91],["H6635","of hosts",92,100],["H7725","and I will turn",102,117],["H0559","unto you, saith",118,133],["H3068","the LORD",134,142],["H6635","of hosts",143,151]]},"1:4":{"text":"Be ye not as your fathers, unto whom the former prophets have cried, saying, Thus saith the LORD of hosts; Turn ye now from your evil ways, and from your evil doings: but they did not hear, nor hearken unto me, saith the LORD.","words":[["H0001","Be ye not as your fathers",0,25],["H7223","unto whom the former",27,47],["H5030","prophets",48,56],["H7121","have cried",57,67],["H0559","saying",69,75],["H0559","Thus saith",77,87],["H3068","the LORD",88,96],["H6635","of hosts",97,105],["H7725","Turn",107,111],["H7451","ye now from your evil",112,133],["H1870","ways",134,138],["H7451","and from your evil",140,158],["H4611","doings",159,165],["H8085","but they did not hear",167,188],["H7181","nor hearken",190,201],["H5002","unto me, saith",202,216],["H3068","the LORD",217,225]]},"1:5":{"text":"Your fathers, where are they? and the prophets, do they live for ever?","words":[["H0001","Your fathers",0,12],["H5030","where are they? and the prophets",14,46],["H2421","do they live",48,60],["H5769","for ever",61,69]]},"1:6":{"text":"But my words and my statutes, which I commanded my servants the prophets, did they not take hold of your fathers? and they returned and said, Like as the LORD of hosts thought to do unto us, according to our ways, and according to our doings, so hath he dealt with us.","words":[["H1697","But my words",0,12],["H2706","and my statutes",13,28],["H6680","which I commanded",30,47],["H5650","my servants",48,59],["H5030","the prophets",60,72],["H5381","did they not take hold",74,96],["H0001","of your fathers",97,112],["H7725","and they returned",114,131],["H0559","and said",132,140],["H3068","Like as the LORD",142,158],["H6635","of hosts",159,167],["H2161","thought",168,175],["H6213","to do",176,181],["H1870","unto us, according to our ways",182,212],["H4611","and according to our doings",214,241],["H6213","so hath he dealt",243,259]]},"1:7":{"text":"Upon the four and twentieth day of the eleventh month, which is the month Sebat, in the second year of Darius, came the word of the LORD unto Zechariah, the son of Berechiah, the son of Iddo the prophet, saying,","words":[["H0702","Upon the four",0,13],["H6242","and twentieth",14,27],["H3117","day",28,31],["H6249","of the eleventh",32,47],["H6240","of the eleventh",32,47],["H2320","month",48,53],["H2320","which is the month",55,73],["H7627","Sebat",74,79],["H8147","in the second",81,94],["H8141","year",95,99],["H1867","of Darius",100,109],["H1697","came the word",111,124],["H3068","of the LORD",125,136],["H2148","unto Zechariah",137,151],["H1121","the son",153,160],["H1296","of Berechiah",161,173],["H1121","the son",175,182],["H5714","of Iddo",183,190],["H5030","the prophet",191,202],["H0559","saying",204,210]]},"1:8":{"text":"I saw by night, and behold a man riding upon a red horse, and he stood among the myrtle trees that were in the bottom; and behind him were there red horses, speckled, and white.","words":[["H7200","I saw",0,5],["H3915","by night",6,14],["H0376","and behold a man",16,32],["H7392","riding",33,39],["H0122","upon a red",40,50],["H5483","horse",51,56],["H5975","and he stood",58,70],["H1918","among the myrtle trees",71,93],["H4699","that were in the bottom",94,117],["H0310","and behind",119,129],["H0122","him were there red",130,148],["H5483","horses",149,155],["H8320","speckled",157,165],["H3836","and white",167,176]]},"1:9":{"text":"Then said I, O my lord, what are these? And the angel that talked with me said unto me, I will shew thee what these be.","words":[["H0559","Then said",0,9],["H0113","I, O my lord",10,22],["H4397","what are these? And the angel",24,53],["H1696","that talked",54,65],["H0559","with me said",66,78],["H7200","unto me, I will shew",79,99]]},"1:10":{"text":"And the man that stood among the myrtle trees answered and said, These are they whom the LORD hath sent to walk to and fro through the earth.","words":[["H0376","And the man",0,11],["H5975","that stood",12,22],["H1918","among the myrtle trees",23,45],["H6030","answered",46,54],["H0559","and said",55,63],["H3068","These are they whom the LORD",65,93],["H7971","hath sent",94,103],["H1980","to walk",104,111],["H0776","to and fro through the earth",112,140]]},"1:11":{"text":"And they answered the angel of the LORD that stood among the myrtle trees, and said, We have walked to and fro through the earth, and, behold, all the earth sitteth still, and is at rest.","words":[["H6030","And they answered",0,17],["H4397","the angel",18,27],["H3068","of the LORD",28,39],["H5975","that stood",40,50],["H1918","among the myrtle trees",51,73],["H0559","and said",75,83],["H1980","We have walked to and fro",85,110],["H0776","through the earth",111,128],["H0776","and, behold, all the earth",130,156],["H3427","sitteth still",157,170],["H8252","and is at rest",172,186]]},"1:12":{"text":"Then the angel of the LORD answered and said, O LORD of hosts, how long wilt thou not have mercy on Jerusalem and on the cities of Judah, against which thou hast had indignation these threescore and ten years?","words":[["H4397","Then the angel",0,14],["H3068","of the LORD",15,26],["H6030","answered",27,35],["H0559","and said",36,44],["H3068","O LORD",46,52],["H6635","of hosts",53,61],["H7355","how long wilt thou not have mercy",63,96],["H3389","on Jerusalem",97,109],["H5892","and on the cities",110,127],["H3063","of Judah",128,136],["H2194","against which thou hast had indignation",138,177],["H7657","these threescore and ten",178,202],["H8141","years",203,208]]},"1:13":{"text":"And the LORD answered the angel that talked with me with good words and comfortable words.","words":[["H3068","And the LORD",0,12],["H6030","answered",13,21],["H4397","the angel",22,31],["H1696","that talked",32,43],["H2896","with me with good",44,61],["H1697","words",62,67],["H5150","and comfortable",68,83],["H1697","words",84,89]]},"1:14":{"text":"So the angel that communed with me said unto me, Cry thou, saying, Thus saith the LORD of hosts; I am jealous for Jerusalem and for Zion with a great jealousy.","words":[["H4397","So the angel",0,12],["H1696","that communed",13,26],["H0559","with me said",27,39],["H7121","unto me, Cry",40,52],["H0559","thou, saying",53,65],["H0559","Thus saith",67,77],["H3068","the LORD",78,86],["H6635","of hosts",87,95],["H7065","I am jealous",97,109],["H3389","for Jerusalem",110,123],["H6726","and for Zion",124,136],["H1419","with a great",137,149],["H7068","jealousy",150,158]]},"1:15":{"text":"And I am very sore displeased with the heathen that are at ease: for I was but a little displeased, and they helped forward the affliction.","words":[["H1419","And I am very",0,13],["H7110","sore",14,18],["H7107","displeased",19,29],["H1471","with the heathen",30,46],["H7600","that are at ease",47,63],["H4592","for I was but a little",65,87],["H7107","displeased",88,98],["H5826","and they helped",100,115],["H7451","forward the affliction",116,138]]},"1:16":{"text":"Therefore thus saith the LORD; I am returned to Jerusalem with mercies: my house shall be built in it, saith the LORD of hosts, and a line shall be stretched forth upon Jerusalem.","words":[["H0559","Therefore thus saith",0,20],["H3068","the LORD",21,29],["H7725","I am returned",31,44],["H3389","to Jerusalem",45,57],["H7356","with mercies",58,70],["H1004","my house",72,80],["H1129","shall be built",81,95],["H5002","in it, saith",96,108],["H3068","the LORD",109,117],["H6635","of hosts",118,126],["H6957","and a line",128,138],["H6961","and a line",128,138],["H5186","shall be stretched forth",139,163],["H3389","upon Jerusalem",164,178]]},"1:17":{"text":"Cry yet, saying, Thus saith the LORD of hosts; My cities through prosperity shall yet be spread abroad; and the LORD shall yet comfort Zion, and shall yet choose Jerusalem.","words":[["H7121","Cry",0,3],["H0559","yet, saying",4,15],["H0559","Thus saith",17,27],["H3068","the LORD",28,36],["H6635","of hosts",37,45],["H5892","My cities",47,56],["H2896","through prosperity",57,75],["H6327","shall yet be spread abroad",76,102],["H3068","and the LORD",104,116],["H5162","shall yet comfort",117,134],["H6726","Zion",135,139],["H0977","and shall yet choose",141,161],["H3389","Jerusalem",162,171]]},"1:18":{"text":"Then lifted I up mine eyes, and saw, and behold four horns.","words":[["H5375","Then lifted I up",0,16],["H5869","mine eyes",17,26],["H7200","and saw",28,35],["H0702","and behold four",37,52],["H7161","horns",53,58]]},"1:19":{"text":"And I said unto the angel that talked with me, What be these? And he answered me, These are the horns which have scattered Judah, Israel, and Jerusalem.","words":[["H0559","And I said",0,10],["H4397","unto the angel",11,25],["H1696","that talked",26,37],["H0559","with me, What be these? And he answered",38,77],["H7161","me, These are the horns",78,101],["H2219","which have scattered",102,122],["H3063","Judah",123,128],["H3478","Israel",130,136],["H3389","and Jerusalem",138,151]]},"1:20":{"text":"And the LORD shewed me four carpenters.","words":[["H3068","And the LORD",0,12],["H7200","shewed",13,19],["H0702","me four",20,27],["H2796","carpenters",28,38]]},"1:21":{"text":"Then said I, What come these to do? And he spake, saying, These are the horns which have scattered Judah, so that no man did lift up his head: but these are come to fray them, to cast out the horns of the Gentiles, which lifted up their horn over the land of Judah to scatter it.","words":[["H0559","Then said",0,9],["H0935","I, What come",10,22],["H6213","these to do",23,34],["H0559","And he spake",36,48],["H0559","saying",50,56],["H7161","These are the horns",58,77],["H2219","which have scattered",78,98],["H3063","Judah",99,104],["H6310","so that",106,113],["H0376","no man",114,120],["H5375","did lift up",121,132],["H7218","his head",133,141],["H0935","but these are come",143,161],["H2729","to fray",162,169],["H3034","them, to cast out",170,187],["H7161","the horns",188,197],["H1471","of the Gentiles",198,213],["H5375","which lifted up",215,230],["H7161","their horn",231,241],["H0776","over the land",242,255],["H3063","of Judah",256,264],["H2219","to scatter",265,275]]},"2:1":{"text":"I lifted up mine eyes again, and looked, and behold a man with a measuring line in his hand.","words":[["H5375","I lifted up",0,11],["H5869","mine eyes",12,21],["H7200","again, and looked",22,39],["H0376","and behold a man",41,57],["H4060","with a measuring",58,74],["H2256","line",75,79],["H3027","in his hand",80,91]]},"2:2":{"text":"Then said I, Whither goest thou? And he said unto me, To measure Jerusalem, to see what is the breadth thereof, and what is the length thereof.","words":[["H0559","Then said",0,9],["H1980","I, Whither goest",10,26],["H0559","thou? And he said",27,44],["H4058","unto me, To measure",45,64],["H3389","Jerusalem",65,74],["H7200","to see",76,82],["H4100","what",83,87],["H7341","is the breadth",88,102],["H0753","thereof, and what is the length",103,134]]},"2:3":{"text":"And, behold, the angel that talked with me went forth, and another angel went out to meet him,","words":[["H4397","And, behold, the angel",0,22],["H1696","that talked",23,34],["H3318","with me went forth",35,53],["H0312","and another",55,66],["H4397","angel",67,72],["H3318","went out",73,81],["H7125","to meet",82,89]]},"2:4":{"text":"And said unto him, Run, speak to this young man, saying, Jerusalem shall be inhabited as towns without walls for the multitude of men and cattle therein:","words":[["H0559","And said",0,8],["H7323","unto him, Run",9,22],["H1696","speak",24,29],["H1975","to this",30,37],["H5288","young man",38,47],["H0559","saying",49,55],["H3389","Jerusalem",57,66],["H3427","shall be inhabited",67,85],["H6519","as towns without walls",86,108],["H7230","for the multitude",109,126],["H0120","of men",127,133],["H0929","and cattle",134,144],["H8432","therein",145,152]]},"2:5":{"text":"For I, saith the LORD, will be unto her a wall of fire round about, and will be the glory in the midst of her.","words":[["H5002","For I, saith",0,12],["H3068","the LORD",13,21],["H2346","will be unto her a wall",23,46],["H0784","of fire",47,54],["H5439","round about",55,66],["H3519","and will be the glory",68,89],["H8432","in the midst",90,102]]},"2:6":{"text":"Ho, ho, come forth, and flee from the land of the north, saith the LORD: for I have spread you abroad as the four winds of the heaven, saith the LORD.","words":[["H1945","Ho",0,2],["H1945","ho",4,6],["H5127","come forth, and flee",8,28],["H0776","from the land",29,42],["H6828","of the north",43,55],["H5002","saith",57,62],["H3068","the LORD",63,71],["H6566","for I have spread you abroad",73,101],["H0702","as the four",102,113],["H7307","winds",114,119],["H8064","of the heaven",120,133],["H5002","saith",135,140],["H3068","the LORD",141,149]]},"2:7":{"text":"Deliver thyself, O Zion, that dwellest with the daughter of Babylon.","words":[["H4422","Deliver",0,7],["H1945","thyself, O",8,18],["H6726","Zion",19,23],["H3427","that dwellest",25,38],["H1323","with the daughter",39,56],["H0894","of Babylon",57,67]]},"2:8":{"text":"For thus saith the LORD of hosts; After the glory hath he sent me unto the nations which spoiled you: for he that toucheth you toucheth the apple of his eye.","words":[["H0559","For thus saith",0,14],["H3068","the LORD",15,23],["H6635","of hosts",24,32],["H0310","After",34,39],["H3519","the glory",40,49],["H7971","hath he sent",50,62],["H1471","me unto the nations",63,82],["H7997","which spoiled",83,96],["H5060","you: for he that toucheth",97,122],["H5060","you toucheth",123,135],["H0892","the apple",136,145],["H5869","of his eye",146,156]]},"2:9":{"text":"For, behold, I will shake mine hand upon them, and they shall be a spoil to their servants: and ye shall know that the LORD of hosts hath sent me.","words":[["H5130","For, behold, I will shake",0,25],["H3027","mine hand",26,35],["H7998","upon them, and they shall be a spoil",36,72],["H5647","to their servants",73,90],["H3045","and ye shall know",92,109],["H3068","that the LORD",110,123],["H6635","of hosts",124,132],["H7971","hath sent",133,142]]},"2:10":{"text":"Sing and rejoice, O daughter of Zion: for, lo, I come, and I will dwell in the midst of thee, saith the LORD.","words":[["H7442","Sing",0,4],["H8055","and rejoice",5,16],["H1323","O daughter",18,28],["H6726","of Zion",29,36],["H0935","for, lo, I come",38,53],["H7931","and I will dwell",55,71],["H8432","in the midst",72,84],["H5002","of thee, saith",85,99],["H3068","the LORD",100,108]]},"2:11":{"text":"And many nations shall be joined to the LORD in that day, and shall be my people: and I will dwell in the midst of thee, and thou shalt know that the LORD of hosts hath sent me unto thee.","words":[["H7227","And many",0,8],["H1471","nations",9,16],["H3867","shall be joined",17,32],["H3068","to the LORD",33,44],["H3117","in that day",45,56],["H5971","and shall be my people",58,80],["H7931","and I will dwell",82,98],["H8432","in the midst",99,111],["H3045","of thee, and thou shalt know",112,140],["H3068","that the LORD",141,154],["H6635","of hosts",155,163],["H7971","hath sent",164,173]]},"2:12":{"text":"And the LORD shall inherit Judah his portion in the holy land, and shall choose Jerusalem again.","words":[["H3068","And the LORD",0,12],["H5157","shall inherit",13,26],["H3063","Judah",27,32],["H2506","his portion",33,44],["H6944","in the holy",45,56],["H0127","land",57,61],["H0977","and shall choose",63,79],["H3389","Jerusalem",80,89]]},"2:13":{"text":"Be silent, O all flesh, before the LORD: for he is raised up out of his holy habitation.","words":[["H2013","Be silent",0,9],["H1320","O all flesh",11,22],["H6440","before",24,30],["H3068","the LORD",31,39],["H5782","for he is raised up",41,60],["H6944","out of his holy",61,76],["H4583","habitation",77,87]]},"3:1":{"text":"And he shewed me Joshua the high priest standing before the angel of the LORD, and Satan standing at his right hand to resist him.","words":[["H7200","And he shewed",0,13],["H3091","me Joshua",14,23],["H1419","the high",24,32],["H3548","priest",33,39],["H5975","standing",40,48],["H6440","before",49,55],["H4397","the angel",56,65],["H3068","of the LORD",66,77],["H7854","and Satan",79,88],["H5975","standing",89,97],["H3225","at his right hand",98,115],["H7853","to resist",116,125]]},"3:2":{"text":"And the LORD said unto Satan, The LORD rebuke thee, O Satan; even the LORD that hath chosen Jerusalem rebuke thee: is not this a brand plucked out of the fire?","words":[["H3068","And the LORD",0,12],["H0559","said",13,17],["H7854","unto Satan",18,28],["H3068","The LORD",30,38],["H1605","rebuke",39,45],["H7854","thee, O Satan",46,59],["H3068","even the LORD",61,74],["H0977","that hath chosen",75,91],["H3389","Jerusalem",92,101],["H1605","rebuke",102,108],["H0181","thee: is not this a brand",109,134],["H5337","plucked",135,142],["H0784","out of the fire",143,158]]},"3:3":{"text":"Now Joshua was clothed with filthy garments, and stood before the angel.","words":[["H3091","Now Joshua",0,10],["H3847","was clothed",11,22],["H6674","with filthy",23,34],["H0899","garments",35,43],["H5975","and stood",45,54],["H6440","before",55,61],["H4397","the angel",62,71]]},"3:4":{"text":"And he answered and spake unto those that stood before him, saying, Take away the filthy garments from him. And unto him he said, Behold, I have caused thine iniquity to pass from thee, and I will clothe thee with change of raiment.","words":[["H6030","And he answered",0,15],["H0559","and spake",16,25],["H5975","unto those that stood",26,47],["H6440","before",48,54],["H0559","him, saying",55,66],["H5493","Take away",68,77],["H6674","the filthy",78,88],["H0899","garments",89,97],["H0559","from him. And unto him he said",98,128],["H7200","Behold",130,136],["H5771","I have caused thine iniquity",138,166],["H5674","to pass",167,174],["H3847","from thee, and I will clothe",175,203],["H4254","thee with change of raiment",204,231]]},"3:5":{"text":"And I said, Let them set a fair mitre upon his head. So they set a fair mitre upon his head, and clothed him with garments. And the angel of the LORD stood by.","words":[["H0559","And I said",0,10],["H7760","Let them set",12,24],["H2889","a fair",25,31],["H6797","mitre",32,37],["H7218","upon his head",38,51],["H7760","So they set",53,64],["H2889","a fair",65,71],["H6797","mitre",72,77],["H7218","upon his head",78,91],["H3847","and clothed",93,104],["H0899","him with garments",105,122],["H4397","And the angel",124,137],["H3068","of the LORD",138,149],["H5975","stood by",150,158]]},"3:6":{"text":"And the angel of the LORD protested unto Joshua, saying,","words":[["H4397","And the angel",0,13],["H3068","of the LORD",14,25],["H5749","protested",26,35],["H3091","unto Joshua",36,47],["H0559","saying",49,55]]},"3:7":{"text":"Thus saith the LORD of hosts; If thou wilt walk in my ways, and if thou wilt keep my charge, then thou shalt also judge my house, and shalt also keep my courts, and I will give thee places to walk among these that stand by.","words":[["H0559","Thus saith",0,10],["H3068","the LORD",11,19],["H6635","of hosts",20,28],["H3212","If thou wilt walk",30,47],["H1870","in my ways",48,58],["H8104","and if thou wilt keep",60,81],["H4931","my charge",82,91],["H1777","then thou shalt also judge",93,119],["H1004","my house",120,128],["H8104","and shalt also keep",130,149],["H2691","my courts",150,159],["H5414","and I will give",161,176],["H4108","thee places to walk",177,196],["H5975","among these that stand by",197,222]]},"3:8":{"text":"Hear now, O Joshua the high priest, thou, and thy fellows that sit before thee: for they are men wondered at: for, behold, I will bring forth my servant the BRANCH.","words":[["H8085","Hear",0,4],["H3091","now, O Joshua",5,18],["H1419","the high",19,27],["H3548","priest",28,34],["H7453","thou, and thy fellows",36,57],["H3427","that sit",58,66],["H6440","before",67,73],["H0582","thee: for they are men",74,96],["H4159","wondered at",97,108],["H0935","for, behold, I will bring forth",110,141],["H5650","my servant",142,152],["H6780","the BRANCH",153,163]]},"3:9":{"text":"For behold the stone that I have laid before Joshua; upon one stone shall be seven eyes: behold, I will engrave the graving thereof, saith the LORD of hosts, and I will remove the iniquity of that land in one day.","words":[["H0068","For behold the stone",0,20],["H5414","that I have laid",21,37],["H6440","before",38,44],["H3091","Joshua",45,51],["H0259","upon one",53,61],["H0068","stone",62,67],["H7651","shall be seven",68,82],["H5869","eyes",83,87],["H6605","behold, I will engrave",89,111],["H6603","the graving",112,123],["H5002","thereof, saith",124,138],["H3068","the LORD",139,147],["H6635","of hosts",148,156],["H4185","and I will remove",158,175],["H5771","the iniquity",176,188],["H0776","of that land",189,201],["H0259","in one",202,208],["H3117","day",209,212]]},"3:10":{"text":"In that day, saith the LORD of hosts, shall ye call every man his neighbour under the vine and under the fig tree.","words":[["H3117","In that day",0,11],["H5002","saith",13,18],["H3068","the LORD",19,27],["H6635","of hosts",28,36],["H7121","shall ye call",38,51],["H0376","every man",52,61],["H7453","his neighbour",62,75],["H1612","under the vine",76,90],["H8384","and under the fig tree",91,113]]},"4:1":{"text":"And the angel that talked with me came again, and waked me, as a man that is wakened out of his sleep,","words":[["H4397","And the angel",0,13],["H1696","that talked",14,25],["H7725","with me came again",26,44],["H5782","and waked",46,55],["H0376","me, as a man",56,68],["H5782","that is wakened",69,84],["H8142","out of his sleep",85,101]]},"4:2":{"text":"And said unto me, What seest thou? And I said, I have looked, and behold a candlestick all of gold, with a bowl upon the top of it, and his seven lamps thereon, and seven pipes to the seven lamps, which are upon the top thereof:","words":[["H0559","And said",0,8],["H7200","unto me, What seest",9,28],["H0559","thou? And I said",29,45],["H7200","I have looked",47,60],["H4501","and behold a candlestick",62,86],["H2091","all of gold",87,98],["H1531","with a bowl",100,111],["H7218","upon the top",112,124],["H7651","of it, and his seven",125,145],["H5216","lamps",146,151],["H7651","thereon, and seven",152,170],["H4166","pipes",171,176],["H7651","to the seven",177,189],["H5216","lamps",190,195],["H7218","which are upon the top",197,219]]},"4:3":{"text":"And two olive trees by it, one upon the right side of the bowl, and the other upon the left side thereof.","words":[["H8147","And two",0,7],["H2132","olive trees",8,19],["H0259","by it, one",20,30],["H3225","upon the right",31,45],["H1543","side of the bowl",46,62],["H0259","and the other",64,77],["H8040","upon the left",78,91]]},"4:4":{"text":"So I answered and spake to the angel that talked with me, saying, What are these, my lord?","words":[["H6030","So I answered",0,13],["H0559","and spake",14,23],["H4397","to the angel",24,36],["H1696","that talked",37,48],["H0559","with me, saying",49,64],["H0113","What are these, my lord",66,89]]},"4:5":{"text":"Then the angel that talked with me answered and said unto me, Knowest thou not what these be? And I said, No, my lord.","words":[["H4397","Then the angel",0,14],["H1696","that talked",15,26],["H6030","with me answered",27,43],["H0559","and said",44,52],["H3045","unto me, Knowest",53,69],["H0559","thou not what these be? And I said",70,104],["H0113","No, my lord",106,117]]},"4:6":{"text":"Then he answered and spake unto me, saying, This is the word of the LORD unto Zerubbabel, saying, Not by might, nor by power, but by my spirit, saith the LORD of hosts.","words":[["H6030","Then he answered",0,16],["H0559","and spake",17,26],["H0559","unto me, saying",27,42],["H1697","This is the word",44,60],["H3068","of the LORD",61,72],["H2216","unto Zerubbabel",73,88],["H0559","saying",90,96],["H2428","Not by might",98,110],["H3581","nor by power",112,124],["H7307","but by my spirit",126,142],["H0559","saith",144,149],["H3068","the LORD",150,158],["H6635","of hosts",159,167]]},"4:7":{"text":"Who art thou, O great mountain? before Zerubbabel thou shalt become a plain: and he shall bring forth the headstone thereof with shoutings, crying, Grace, grace unto it.","words":[["H1419","Who art thou, O great",0,21],["H2022","mountain",22,30],["H6440","before",32,38],["H2216","Zerubbabel",39,49],["H4334","thou shalt become a plain",50,75],["H3318","and he shall bring forth",77,101],["H0068","the headstone",102,115],["H7222","the headstone",102,115],["H8663","thereof with shoutings",116,138],["H2580","crying, Grace",140,153],["H2580","grace",155,160]]},"4:8":{"text":"Moreover the word of the LORD came unto me, saying,","words":[["H1697","Moreover the word",0,17],["H3068","of the LORD",18,29],["H0559","came unto me, saying",30,50]]},"4:9":{"text":"The hands of Zerubbabel have laid the foundation of this house; his hands shall also finish it; and thou shalt know that the LORD of hosts hath sent me unto you.","words":[["H3027","The hands",0,9],["H2216","of Zerubbabel",10,23],["H3245","have laid the foundation",24,48],["H1004","of this house",49,62],["H3027","his hands",64,73],["H1214","shall also finish",74,91],["H3045","it; and thou shalt know",92,115],["H3068","that the LORD",116,129],["H6635","of hosts",130,138],["H7971","hath sent",139,148]]},"4:10":{"text":"For who hath despised the day of small things? for they shall rejoice, and shall see the plummet in the hand of Zerubbabel with those seven; they are the eyes of the LORD, which run to and fro through the whole earth.","words":[["H0936","For who hath despised",0,21],["H3117","the day",22,29],["H6996","of small things",30,45],["H8055","for they shall rejoice",47,69],["H7200","and shall see",71,84],["H0068","the plummet",85,96],["H0913","the plummet",85,96],["H3027","in the hand",97,108],["H2216","of Zerubbabel",109,122],["H7651","with those seven",123,139],["H5869","they are the eyes",141,158],["H3068","of the LORD",159,170],["H7751","which run to and fro",172,192],["H0776","through the whole earth",193,216]]},"4:11":{"text":"Then answered I, and said unto him, What are these two olive trees upon the right side of the candlestick and upon the left side thereof?","words":[["H6030","Then answered",0,13],["H0559","I, and said",14,25],["H8147","unto him, What are these two",26,54],["H2132","olive trees",55,66],["H3225","upon the right",67,81],["H4501","side of the candlestick",82,105],["H8040","and upon the left",106,123]]},"4:12":{"text":"And I answered again, and said unto him, What be these two olive branches which through the two golden pipes empty the golden oil out of themselves?","words":[["H6030","And I answered",0,14],["H8145","again",15,20],["H0559","and said",22,30],["H8147","unto him, What be these two",31,58],["H2132","olive",59,64],["H7641","branches",65,73],["H3027","which through",74,87],["H8147","the two",88,95],["H2091","golden",96,102],["H6804","pipes",103,108],["H7324","empty",109,114],["H2091","the golden",115,125]]},"4:13":{"text":"And he answered me and said, Knowest thou not what these be? And I said, No, my lord.","words":[["H0559","And he answered",0,15],["H0559","me and said",16,27],["H3045","Knowest",29,36],["H0559","thou not what these be? And I said",37,71],["H0113","No, my lord",73,84]]},"4:14":{"text":"Then said he, These are the two anointed ones, that stand by the Lord of the whole earth.","words":[["H0559","Then said",0,9],["H8147","he, These are the two",10,31],["H3323","anointed",32,40],["H1121","ones",41,45],["H5975","that stand",47,57],["H0113","by the Lord",58,69],["H0776","of the whole earth",70,88]]},"5:1":{"text":"Then I turned, and lifted up mine eyes, and looked, and behold a flying roll.","words":[["H7725","Then I turned",0,13],["H5375","and lifted up",15,28],["H5869","mine eyes",29,38],["H7200","and looked",40,50],["H5774","and behold a flying",52,71],["H4039","roll",72,76]]},"5:2":{"text":"And he said unto me, What seest thou? And I answered, I see a flying roll; the length thereof is twenty cubits, and the breadth thereof ten cubits.","words":[["H0559","And he said",0,11],["H7200","unto me, What seest",12,31],["H0559","thou? And I answered",32,52],["H7200","I see",54,59],["H5774","a flying",60,68],["H4039","roll",69,73],["H0753","the length",75,85],["H6242","thereof is twenty",86,103],["H0520","cubits",104,110],["H7341","and the breadth",112,127],["H6235","thereof ten",128,139],["H0520","cubits",140,146]]},"5:3":{"text":"Then said he unto me, This is the curse that goeth forth over the face of the whole earth: for every one that stealeth shall be cut off as on this side according to it; and every one that sweareth shall be cut off as on that side according to it.","words":[["H0559","Then said",0,9],["H0423","he unto me, This is the curse",10,39],["H3318","that goeth forth",40,56],["H6440","over the face",57,70],["H0776","of the whole earth",71,89],["H1589","for every one that stealeth",91,118],["H5352","shall be cut off",119,135],["H3644","as on this side according",136,161],["H7650","to it; and every one that sweareth",162,196],["H5352","shall be cut off",197,213],["H3644","as on that side according",214,239]]},"5:4":{"text":"I will bring it forth, saith the LORD of hosts, and it shall enter into the house of the thief, and into the house of him that sweareth falsely by my name: and it shall remain in the midst of his house, and shall consume it with the timber thereof and the stones thereof.","words":[["H3318","I will bring it forth",0,21],["H5002","saith",23,28],["H3068","the LORD",29,37],["H6635","of hosts",38,46],["H0935","and it shall enter",48,66],["H1004","into the house",67,81],["H1590","of the thief",82,94],["H1004","and into the house",96,114],["H7650","of him that sweareth",115,135],["H8267","falsely",136,143],["H8034","by my name",144,154],["H3885","and it shall remain",156,175],["H8432","in the midst",176,188],["H1004","of his house",189,201],["H3615","and shall consume",203,220],["H6086","it with the timber",221,239],["H0068","thereof and the stones",240,262]]},"5:5":{"text":"Then the angel that talked with me went forth, and said unto me, Lift up now thine eyes, and see what is this that goeth forth.","words":[["H4397","Then the angel",0,14],["H1696","that talked",15,26],["H3318","with me went forth",27,45],["H0559","and said",47,55],["H5375","unto me, Lift up",56,72],["H5869","now thine eyes",73,87],["H7200","and see",89,96],["H3318","what is this that goeth forth",97,126]]},"5:6":{"text":"And I said, What is it? And he said, This is an ephah that goeth forth. He said moreover, This is their resemblance through all the earth.","words":[["H0559","And I said",0,10],["H0559","What is it? And he said",12,35],["H0374","This is an ephah",37,53],["H3318","that goeth forth",54,70],["H0559","He said",72,79],["H5869","moreover, This is their resemblance",80,115],["H0776","through all the earth",116,137]]},"5:7":{"text":"And, behold, there was lifted up a talent of lead: and this is a woman that sitteth in the midst of the ephah.","words":[["H5375","And, behold, there was lifted up",0,32],["H3603","a talent",33,41],["H5777","of lead",42,49],["H0259","and this is a",51,64],["H0802","woman",65,70],["H3427","that sitteth",71,83],["H8432","in the midst",84,96],["H0374","of the ephah",97,109]]},"5:8":{"text":"And he said, This is wickedness. And he cast it into the midst of the ephah; and he cast the weight of lead upon the mouth thereof.","words":[["H0559","And he said",0,11],["H7564","This is wickedness",13,31],["H7993","And he cast",33,44],["H8432","it into the midst",45,62],["H0374","of the ephah",63,75],["H7993","and he cast",77,88],["H0068","the weight",89,99],["H5777","of lead",100,107],["H6310","upon the mouth",108,122]]},"5:9":{"text":"Then lifted I up mine eyes, and looked, and, behold, there came out two women, and the wind was in their wings; for they had wings like the wings of a stork: and they lifted up the ephah between the earth and the heaven.","words":[["H5375","Then lifted I up",0,16],["H5869","mine eyes",17,26],["H7200","and looked",28,38],["H3318","and, behold, there came out",40,67],["H8147","two",68,71],["H0802","women",72,77],["H7307","and the wind",79,91],["H3671","was in their wings",92,110],["H2007","for they had",112,124],["H3671","wings",125,130],["H3671","like the wings",131,145],["H2624","of a stork",146,156],["H5375","and they lifted up",158,176],["H0374","the ephah",177,186],["H0776","between the earth",187,204],["H8064","and the heaven",205,219]]},"5:10":{"text":"Then said I to the angel that talked with me, Whither do these bear the ephah?","words":[["H0559","Then said",0,9],["H4397","I to the angel",10,24],["H1696","that talked",25,36],["H3212","with me, Whither do these bear",37,67],["H0374","the ephah",68,77]]},"5:11":{"text":"And he said unto me, To build it an house in the land of Shinar: and it shall be established, and set there upon her own base.","words":[["H0559","And he said",0,11],["H1129","unto me, To build",12,29],["H1004","it an house",30,41],["H0776","in the land",42,53],["H8152","of Shinar",54,63],["H3559","and it shall be established",65,92],["H3240","and set",94,101],["H4369","there upon her own base",102,125]]},"6:1":{"text":"And I turned, and lifted up mine eyes, and looked, and, behold, there came four chariots out from between two mountains; and the mountains were mountains of brass.","words":[["H7725","And I turned",0,12],["H5375","and lifted up",14,27],["H5869","mine eyes",28,37],["H7200","and looked",39,49],["H3318","and, behold, there came",51,74],["H0702","four",75,79],["H4818","chariots",80,88],["H3318","out",89,92],["H8147","from between two",93,109],["H2022","mountains",110,119],["H2022","and the mountains",121,138],["H2022","were mountains",139,153],["H5178","of brass",154,162]]},"6:2":{"text":"In the first chariot were red horses; and in the second chariot black horses;","words":[["H7223","In the first",0,12],["H4818","chariot",13,20],["H0122","were red",21,29],["H5483","horses",30,36],["H8145","and in the second",38,55],["H4818","chariot",56,63],["H7838","black",64,69],["H5483","horses",70,76]]},"6:3":{"text":"And in the third chariot white horses; and in the fourth chariot grisled and bay horses.","words":[["H7992","And in the third",0,16],["H4818","chariot",17,24],["H3836","white",25,30],["H5483","horses",31,37],["H7243","and in the fourth",39,56],["H4818","chariot",57,64],["H1261","grisled",65,72],["H0554","and bay",73,80],["H5483","horses",81,87]]},"6:4":{"text":"Then I answered and said unto the angel that talked with me, What are these, my lord?","words":[["H6030","Then I answered",0,15],["H0559","and said",16,24],["H4397","unto the angel",25,39],["H1696","that talked",40,51],["H0113","with me, What are these, my lord",52,84]]},"6:5":{"text":"And the angel answered and said unto me, These are the four spirits of the heavens, which go forth from standing before the Lord of all the earth.","words":[["H4397","And the angel",0,13],["H6030","answered",14,22],["H0559","and said",23,31],["H0702","unto me, These are the four",32,59],["H7307","spirits",60,67],["H8064","of the heavens",68,82],["H3318","which go forth",84,98],["H3320","from standing",99,112],["H0113","before the Lord",113,128],["H0776","of all the earth",129,145]]},"6:6":{"text":"The black horses which are therein go forth into the north country; and the white go forth after them; and the grisled go forth toward the south country.","words":[["H7838","The black",0,9],["H5483","horses",10,16],["H3318","which are therein go forth",17,43],["H6828","into the north",44,58],["H0776","country",59,66],["H3836","and the white",68,81],["H3318","go forth",82,90],["H0310","after",91,96],["H1261","them; and the grisled",97,118],["H3318","go forth",119,127],["H8486","toward the south",128,144],["H0776","country",145,152]]},"6:7":{"text":"And the bay went forth, and sought to go that they might walk to and fro through the earth: and he said, Get you hence, walk to and fro through the earth. So they walked to and fro through the earth.","words":[["H0554","And the bay",0,11],["H3318","went forth",12,22],["H1245","and sought",24,34],["H3212","to go",35,40],["H1980","that they might walk to and fro",41,72],["H0776","through the earth",73,90],["H0559","and he said",92,103],["H3212","Get you hence",105,118],["H1980","walk to and fro",120,135],["H0776","through the earth",136,153],["H1980","So they walked to and fro",155,180],["H0776","through the earth",181,198]]},"6:8":{"text":"Then cried he upon me, and spake unto me, saying, Behold, these that go toward the north country have quieted my spirit in the north country.","words":[["H2199","Then cried",0,10],["H0853","he upon",11,18],["H1696","me, and spake",19,32],["H0559","unto me, saying",33,48],["H7200","Behold",50,56],["H3318","these that go",58,71],["H6828","toward the north",72,88],["H0776","country",89,96],["H5117","have quieted",97,109],["H7307","my spirit",110,119],["H6828","in the north",120,132],["H0776","country",133,140]]},"6:9":{"text":"And the word of the LORD came unto me, saying,","words":[["H1697","And the word",0,12],["H3068","of the LORD",13,24],["H0559","came unto me, saying",25,45]]},"6:10":{"text":"Take of them of the captivity, even of Heldai, of Tobijah, and of Jedaiah, which are come from Babylon, and come thou the same day, and go into the house of Josiah the son of Zephaniah;","words":[["H3947","Take",0,4],["H1473","of them of the captivity",5,29],["H2469","even of Heldai",31,45],["H2900","of Tobijah",47,57],["H3048","and of Jedaiah",59,73],["H0935","which are come",75,89],["H0894","from Babylon",90,102],["H0935","and come",104,112],["H3117","thou the same day",113,130],["H0935","and go",132,138],["H1004","into the house",139,153],["H2977","of Josiah",154,163],["H1121","the son",164,171],["H6846","of Zephaniah",172,184]]},"6:11":{"text":"Then take silver and gold, and make crowns, and set them upon the head of Joshua the son of Josedech, the high priest;","words":[["H3947","Then take",0,9],["H3701","silver",10,16],["H2091","and gold",17,25],["H6213","and make",27,35],["H5850","crowns",36,42],["H7760","and set",44,51],["H7218","them upon the head",52,70],["H3091","of Joshua",71,80],["H1121","the son",81,88],["H3087","of Josedech",89,100],["H1419","the high",102,110],["H3548","priest",111,117]]},"6:12":{"text":"And speak unto him, saying, Thus speaketh the LORD of hosts, saying, Behold the man whose name is The BRANCH; and he shall grow up out of his place, and he shall build the temple of the LORD:","words":[["H0559","And speak",0,9],["H0559","unto him, saying",10,26],["H0559","Thus speaketh",28,41],["H3068","the LORD",42,50],["H6635","of hosts",51,59],["H0559","saying",61,67],["H0376","Behold the man",69,83],["H8034","whose name",84,94],["H6780","is The BRANCH",95,108],["H6779","and he shall grow up",110,130],["H1129","out of his place, and he shall build",131,167],["H1964","the temple",168,178],["H3068","of the LORD",179,190]]},"6:13":{"text":"Even he shall build the temple of the LORD; and he shall bear the glory, and shall sit and rule upon his throne; and he shall be a priest upon his throne: and the counsel of peace shall be between them both.","words":[["H1129","Even he shall build",0,19],["H1964","the temple",20,30],["H3068","of the LORD",31,42],["H5375","and he shall bear",44,61],["H1935","the glory",62,71],["H3427","and shall sit",73,86],["H4910","and rule",87,95],["H3678","upon his throne",96,111],["H3548","and he shall be a priest",113,137],["H3678","upon his throne",138,153],["H6098","and the counsel",155,170],["H7965","of peace",171,179],["H8147","shall be between them both",180,206]]},"6:14":{"text":"And the crowns shall be to Helem, and to Tobijah, and to Jedaiah, and to Hen the son of Zephaniah, for a memorial in the temple of the LORD.","words":[["H5850","And the crowns",0,14],["H2494","shall be to Helem",15,32],["H2900","and to Tobijah",34,48],["H3048","and to Jedaiah",50,64],["H2581","and to Hen",66,76],["H1121","the son",77,84],["H6846","of Zephaniah",85,97],["H2146","for a memorial",99,113],["H1964","in the temple",114,127],["H3068","of the LORD",128,139]]},"6:15":{"text":"And they that are far off shall come and build in the temple of the LORD, and ye shall know that the LORD of hosts hath sent me unto you. And this shall come to pass, if ye will diligently obey the voice of the LORD your God.","words":[["H7350","And they that are far off",0,25],["H0935","shall come",26,36],["H1129","and build",37,46],["H1964","in the temple",47,60],["H3068","of the LORD",61,72],["H3045","and ye shall know",74,91],["H3068","that the LORD",92,105],["H6635","of hosts",106,114],["H7971","hath sent",115,124],["H8085","me unto you. And this shall come to pass, if ye will diligently",125,188],["H8085","obey",189,193],["H6963","the voice",194,203],["H3068","of the LORD",204,215],["H0430","your God",216,224]]},"7:1":{"text":"And it came to pass in the fourth year of king Darius, that the word of the LORD came unto Zechariah in the fourth day of the ninth month, even in Chisleu;","words":[["H0702","And it came to pass in the fourth",0,33],["H8141","year",34,38],["H4428","of king",39,46],["H1867","Darius",47,53],["H1697","that the word",55,68],["H3068","of the LORD",69,80],["H2148","came unto Zechariah",81,100],["H0702","in the fourth",101,114],["H8671","day of the ninth",115,131],["H2320","month",132,137],["H3691","even in Chisleu",139,154]]},"7:2":{"text":"When they had sent unto the house of God Sherezer and Regemmelech, and their men, to pray before the LORD,","words":[["H7971","When they had sent",0,18],["H1004","unto the house",19,33],["H0410","of God",34,40],["H8272","Sherezer",41,49],["H7278","and Regemmelech",50,65],["H0582","and their men",67,80],["H2470","to pray",82,89],["H6440","before",90,96],["H3068","the LORD",97,105]]},"7:3":{"text":"And to speak unto the priests which were in the house of the LORD of hosts, and to the prophets, saying, Should I weep in the fifth month, separating myself, as I have done these so many years?","words":[["H0559","And to speak",0,12],["H3548","unto the priests",13,29],["H1004","which were in the house",30,53],["H3068","of the LORD",54,65],["H6635","of hosts",66,74],["H5030","and to the prophets",76,95],["H0559","saying",97,103],["H1058","Should I weep",105,118],["H2549","in the fifth",119,131],["H2320","month",132,137],["H5144","separating",139,149],["H6213","myself, as I have done",150,172],["H8141","these so many years",173,192]]},"7:4":{"text":"Then came the word of the LORD of hosts unto me, saying,","words":[["H1697","Then came the word",0,18],["H3068","of the LORD",19,30],["H6635","of hosts",31,39],["H0559","unto me, saying",40,55]]},"7:5":{"text":"Speak unto all the people of the land, and to the priests, saying, When ye fasted and mourned in the fifth and seventh month, even those seventy years, did ye at all fast unto me, even to me?","words":[["H0559","Speak",0,5],["H5971","unto all the people",6,25],["H0776","of the land",26,37],["H3548","and to the priests",39,57],["H0559","saying",59,65],["H6684","When ye fasted",67,81],["H5594","and mourned",82,93],["H2549","in the fifth",94,106],["H7637","and seventh",107,118],["H7657","month, even those seventy",119,144],["H8141","years",145,150],["H6684","did ye at all",152,165],["H6684","fast",166,170]]},"7:6":{"text":"And when ye did eat, and when ye did drink, did not ye eat for yourselves, and drink for yourselves?","words":[["H0398","And when ye did eat",0,19],["H8354","and when ye did drink",21,42],["H0398","did not ye eat",44,58],["H8354","for yourselves, and drink",59,84]]},"7:7":{"text":"Should ye not hear the words which the LORD hath cried by the former prophets, when Jerusalem was inhabited and in prosperity, and the cities thereof round about her, when men inhabited the south and the plain?","words":[["H1697","Should ye not hear the words",0,28],["H3068","which the LORD",29,43],["H7121","hath cried",44,54],["H3027","by",55,57],["H7223","the former",58,68],["H5030","prophets",69,77],["H3389","when Jerusalem",79,93],["H3427","was inhabited",94,107],["H7961","and in prosperity",108,125],["H5892","and the cities",127,141],["H5439","thereof round about her",142,165],["H3427","when men inhabited",167,185],["H5045","the south",186,195],["H8219","and the plain",196,209]]},"7:8":{"text":"And the word of the LORD came unto Zechariah, saying,","words":[["H1697","And the word",0,12],["H3068","of the LORD",13,24],["H2148","came unto Zechariah",25,44],["H0559","saying",46,52]]},"7:9":{"text":"Thus speaketh the LORD of hosts, saying, Execute true judgment, and shew mercy and compassions every man to his brother:","words":[["H0559","Thus speaketh",0,13],["H3068","the LORD",14,22],["H6635","of hosts",23,31],["H0559","saying",33,39],["H8199","Execute",41,48],["H0571","true",49,53],["H4941","judgment",54,62],["H6213","and shew",64,72],["H2617","mercy",73,78],["H7356","and compassions",79,94],["H0376","every man",95,104],["H0251","to his brother",105,119]]},"7:10":{"text":"And oppress not the widow, nor the fatherless, the stranger, nor the poor; and let none of you imagine evil against his brother in your heart.","words":[["H6231","And oppress",0,11],["H0490","not the widow",12,25],["H3490","nor the fatherless",27,45],["H1616","the stranger",47,59],["H6041","nor the poor",61,73],["H2803","and let none of you imagine",75,102],["H7451","evil",103,107],["H0376","against",108,115],["H0251","his brother",116,127],["H3824","in your heart",128,141]]},"7:11":{"text":"But they refused to hearken, and pulled away the shoulder, and stopped their ears, that they should not hear.","words":[["H3985","But they refused",0,16],["H7181","to hearken",17,27],["H5414","and pulled away",29,44],["H5637","and pulled away",29,44],["H3802","the shoulder",45,57],["H3513","and stopped",59,70],["H0241","their ears",71,81],["H8085","that they should not hear",83,108]]},"7:12":{"text":"Yea, they made their hearts as an adamant stone, lest they should hear the law, and the words which the LORD of hosts hath sent in his spirit by the former prophets: therefore came a great wrath from the LORD of hosts.","words":[["H7760","Yea, they made",0,14],["H3820","their hearts",15,27],["H8068","as an adamant stone",28,47],["H8085","lest they should hear",49,70],["H8451","the law",71,78],["H1697","and the words",80,93],["H3068","which the LORD",94,108],["H6635","of hosts",109,117],["H7971","hath sent",118,127],["H7307","in his spirit",128,141],["H3027","by",142,144],["H7223","the former",145,155],["H5030","prophets",156,164],["H1419","therefore came a great",166,188],["H7110","wrath",189,194],["H3068","from the LORD",195,208],["H6635","of hosts",209,217]]},"7:13":{"text":"Therefore it is come to pass, that as he cried, and they would not hear; so they cried, and I would not hear, saith the LORD of hosts:","words":[["H7121","Therefore it is come to pass, that as he cried",0,46],["H8085","and they would not hear",48,71],["H7121","so they cried",73,86],["H8085","and I would not hear",88,108],["H0559","saith",110,115],["H3068","the LORD",116,124],["H6635","of hosts",125,133]]},"7:14":{"text":"But I scattered them with a whirlwind among all the nations whom they knew not. Thus the land was desolate after them, that no man passed through nor returned: for they laid the pleasant land desolate.","words":[["H5590","But I scattered them with a whirlwind",0,37],["H1471","among all the nations",38,59],["H3045","whom they knew",60,74],["H0776","not. Thus the land",75,93],["H8074","was desolate",94,106],["H0310","after",107,112],["H5674","them, that no man passed through",113,145],["H7725","nor returned",146,158],["H7760","for they laid",160,173],["H2532","the pleasant",174,186],["H0776","land",187,191],["H8047","desolate",192,200]]},"8:1":{"text":"Again the word of the LORD of hosts came to me, saying,","words":[["H1697","Again the word",0,14],["H3068","of the LORD",15,26],["H6635","of hosts",27,35],["H0559","came to me, saying",36,54]]},"8:2":{"text":"Thus saith the LORD of hosts; I was jealous for Zion with great jealousy, and I was jealous for her with great fury.","words":[["H0559","Thus saith",0,10],["H3068","the LORD",11,19],["H6635","of hosts",20,28],["H7065","I was jealous",30,43],["H6726","for Zion",44,52],["H1419","with great",53,63],["H7068","jealousy",64,72],["H7065","and I was jealous",74,91],["H1419","for her with great",92,110],["H2534","fury",111,115]]},"8:3":{"text":"Thus saith the LORD; I am returned unto Zion, and will dwell in the midst of Jerusalem: and Jerusalem shall be called a city of truth; and the mountain of the LORD of hosts the holy mountain.","words":[["H0559","Thus saith",0,10],["H3068","the LORD",11,19],["H7725","I am returned",21,34],["H6726","unto Zion",35,44],["H7931","and will dwell",46,60],["H8432","in the midst",61,73],["H3389","of Jerusalem",74,86],["H3389","and Jerusalem",88,101],["H7121","shall be called",102,117],["H5892","a city",118,124],["H0571","of truth",125,133],["H2022","and the mountain",135,151],["H3068","of the LORD",152,163],["H6635","of hosts",164,172],["H6944","the holy",173,181],["H2022","mountain",182,190]]},"8:4":{"text":"Thus saith the LORD of hosts; There shall yet old men and old women dwell in the streets of Jerusalem, and every man with his staff in his hand for very age.","words":[["H0559","Thus saith",0,10],["H3068","the LORD",11,19],["H6635","of hosts",20,28],["H2205","There shall yet old men",30,53],["H2205","and old women",54,67],["H3427","dwell",68,73],["H7339","in the streets",74,88],["H3389","of Jerusalem",89,101],["H0376","and every man",103,116],["H4938","with his staff",117,131],["H3027","in his hand",132,143],["H7230","for very",144,152],["H3117","age",153,156]]},"8:5":{"text":"And the streets of the city shall be full of boys and girls playing in the streets thereof.","words":[["H7339","And the streets",0,15],["H5892","of the city",16,27],["H4390","shall be full",28,41],["H3206","of boys",42,49],["H3207","and girls",50,59],["H7832","playing",60,67],["H7339","in the streets",68,82]]},"8:6":{"text":"Thus saith the LORD of hosts; If it be marvellous in the eyes of the remnant of this people in these days, should it also be marvellous in mine eyes? saith the LORD of hosts.","words":[["H0559","Thus saith",0,10],["H3068","the LORD",11,19],["H6635","of hosts",20,28],["H6381","If it be marvellous",30,49],["H5869","in the eyes",50,61],["H7611","of the remnant",62,76],["H5971","of this people",77,91],["H3117","in these days",92,105],["H6381","should it also be marvellous",107,135],["H5869","in mine eyes",136,148],["H5002","saith",150,155],["H3068","the LORD",156,164],["H6635","of hosts",165,173]]},"8:7":{"text":"Thus saith the LORD of hosts; Behold, I will save my people from the east country, and from the west country;","words":[["H0559","Thus saith",0,10],["H3068","the LORD",11,19],["H6635","of hosts",20,28],["H3467","Behold, I will save",30,49],["H5971","my people",50,59],["H4217","from the east",60,73],["H0776","country",74,81],["H3996","and from the west",83,100],["H8121","and from the west",83,100],["H0776","country",101,108]]},"8:8":{"text":"And I will bring them, and they shall dwell in the midst of Jerusalem: and they shall be my people, and I will be their God, in truth and in righteousness.","words":[["H0935","And I will bring",0,16],["H7931","them, and they shall dwell",17,43],["H8432","in the midst",44,56],["H3389","of Jerusalem",57,69],["H5971","and they shall be my people",71,98],["H0430","and I will be their God",100,123],["H0571","in truth",125,133],["H6666","and in righteousness",134,154]]},"8:9":{"text":"Thus saith the LORD of hosts; Let your hands be strong, ye that hear in these days these words by the mouth of the prophets, which were in the day that the foundation of the house of the LORD of hosts was laid, that the temple might be built.","words":[["H0559","Thus saith",0,10],["H3068","the LORD",11,19],["H6635","of hosts",20,28],["H3027","Let your hands",30,44],["H2388","be strong",45,54],["H8085","ye that hear",56,68],["H3117","in these days",69,82],["H1697","these words",83,94],["H6310","by the mouth",95,107],["H5030","of the prophets",108,123],["H3117","which were in the day",125,146],["H3245","that the foundation",147,166],["H1004","of the house",167,179],["H3068","of the LORD",180,191],["H6635","of hosts",192,200],["H3245","was laid",201,209],["H1964","that the temple",211,226],["H1129","might be built",227,241]]},"8:10":{"text":"For before these days there was no hire for man, nor any hire for beast; neither was there any peace to him that went out or came in because of the affliction: for I set all men every one against his neighbour.","words":[["H6440","For before",0,10],["H3117","these days",11,21],["H1961","there was",22,31],["H7939","no hire",32,39],["H0120","for man",40,47],["H7939","nor any hire",49,61],["H0929","for beast",62,71],["H7965","neither was there any peace",73,100],["H3318","to him that went out",101,121],["H0935","or came in",122,132],["H6862","because of the affliction",133,158],["H7971","for I set",160,169],["H0120","all men",170,177],["H0376","every one",178,187],["H7453","against his neighbour",188,209]]},"8:11":{"text":"But now I will not be unto the residue of this people as in the former days, saith the LORD of hosts.","words":[["H7611","But now I will not be unto the residue",0,38],["H5971","of this people",39,53],["H7223","as in the former",54,70],["H3117","days",71,75],["H5002","saith",77,82],["H3068","the LORD",83,91],["H6635","of hosts",92,100]]},"8:12":{"text":"For the seed shall be prosperous; the vine shall give her fruit, and the ground shall give her increase, and the heavens shall give their dew; and I will cause the remnant of this people to possess all these things.","words":[["H2233","For the seed",0,12],["H7965","shall be prosperous",13,32],["H1612","the vine",34,42],["H5414","shall give",43,53],["H6529","her fruit",54,63],["H0776","and the ground",65,79],["H5414","shall give",80,90],["H2981","her increase",91,103],["H8064","and the heavens",105,120],["H5414","shall give",121,131],["H2919","their dew",132,141],["H7611","and I will cause the remnant",143,171],["H5971","of this people",172,186],["H5157","to possess",187,197]]},"8:13":{"text":"And it shall come to pass, that as ye were a curse among the heathen, O house of Judah, and house of Israel; so will I save you, and ye shall be a blessing: fear not, but let your hands be strong.","words":[["H7045","And it shall come to pass, that as ye were a curse",0,50],["H1471","among the heathen",51,68],["H1004","O house",70,77],["H3063","of Judah",78,86],["H1004","and house",88,97],["H3478","of Israel",98,107],["H3467","so will I save",109,123],["H1293","you, and ye shall be a blessing",124,155],["H3372","fear",157,161],["H3027","not, but let your hands",162,185],["H2388","be strong",186,195]]},"8:14":{"text":"For thus saith the LORD of hosts; As I thought to punish you, when your fathers provoked me to wrath, saith the LORD of hosts, and I repented not:","words":[["H0559","For thus saith",0,14],["H3068","the LORD",15,23],["H6635","of hosts",24,32],["H2161","As I thought",34,46],["H7489","to punish",47,56],["H0001","you, when your fathers",57,79],["H7107","provoked me to wrath",80,100],["H0559","saith",102,107],["H3068","the LORD",108,116],["H6635","of hosts",117,125],["H5162","and I repented",127,141]]},"8:15":{"text":"So again have I thought in these days to do well unto Jerusalem and to the house of Judah: fear ye not.","words":[["H7725","So again",0,8],["H2161","have I thought",9,23],["H3117","in these days",24,37],["H3190","to do well",38,48],["H3389","unto Jerusalem",49,63],["H1004","and to the house",64,80],["H3063","of Judah",81,89],["H3372","fear",91,95]]},"8:16":{"text":"These are the things that ye shall do; Speak ye every man the truth to his neighbour; execute the judgment of truth and peace in your gates:","words":[["H1697","These are the things",0,20],["H6213","that ye shall do",21,37],["H1696","Speak",39,44],["H0376","ye every man",45,57],["H0571","the truth",58,67],["H7453","to his neighbour",68,84],["H8199","execute",86,93],["H4941","the judgment",94,106],["H0571","of truth",107,115],["H7965","and peace",116,125],["H8179","in your gates",126,139]]},"8:17":{"text":"And let none of you imagine evil in your hearts against his neighbour; and love no false oath: for all these are things that I hate, saith the LORD.","words":[["H0376","And let none",0,12],["H2803","of you imagine",13,27],["H7451","evil",28,32],["H3824","in your hearts",33,47],["H7453","against his neighbour",48,69],["H0157","and love",71,79],["H8267","no false",80,88],["H7621","oath",89,93],["H8130","for all these are things that I hate",95,131],["H5002","saith",133,138],["H3068","the LORD",139,147]]},"8:18":{"text":"And the word of the LORD of hosts came unto me, saying,","words":[["H1697","And the word",0,12],["H3068","of the LORD",13,24],["H6635","of hosts",25,33],["H0559","came unto me, saying",34,54]]},"8:19":{"text":"Thus saith the LORD of hosts; The fast of the fourth month, and the fast of the fifth, and the fast of the seventh, and the fast of the tenth, shall be to the house of Judah joy and gladness, and cheerful feasts; therefore love the truth and peace.","words":[["H0559","Thus saith",0,10],["H3068","the LORD",11,19],["H6635","of hosts",20,28],["H6685","The fast",30,38],["H7243","of the fourth",39,52],["H6685","month, and the fast",53,72],["H2549","of the fifth",73,85],["H6685","and the fast",87,99],["H7637","of the seventh",100,114],["H6685","and the fast",116,128],["H6224","of the tenth",129,141],["H1004","shall be to the house",143,164],["H3063","of Judah",165,173],["H8342","joy",174,177],["H8057","and gladness",178,190],["H2896","and cheerful",192,204],["H4150","feasts",205,211],["H0157","therefore love",213,227],["H0571","the truth",228,237],["H7965","and peace",238,247]]},"8:20":{"text":"Thus saith the LORD of hosts; It shall yet come to pass, that there shall come people, and the inhabitants of many cities:","words":[["H0559","Thus saith",0,10],["H3068","the LORD",11,19],["H6635","of hosts",20,28],["H0935","It shall yet come to pass, that there shall come",30,78],["H5971","people",79,85],["H3427","and the inhabitants",87,106],["H7227","of many",107,114],["H5892","cities",115,121]]},"8:21":{"text":"And the inhabitants of one city shall go to another, saying, Let us go speedily to pray before the LORD, and to seek the LORD of hosts: I will go also.","words":[["H3427","And the inhabitants",0,19],["H0259","of one",20,26],["H1980","city shall go",27,40],["H0259","to another",41,51],["H0559","saying",53,59],["H3212","Let us go",61,70],["H1980","speedily",71,79],["H2470","to pray",80,87],["H6440","before",88,94],["H3068","the LORD",95,103],["H1245","and to seek",105,116],["H3068","the LORD",117,125],["H6635","of hosts",126,134],["H3212","I will go",136,145]]},"8:22":{"text":"Yea, many people and strong nations shall come to seek the LORD of hosts in Jerusalem, and to pray before the LORD.","words":[["H7227","Yea, many",0,9],["H5971","people",10,16],["H6099","and strong",17,27],["H1471","nations",28,35],["H0935","shall come",36,46],["H1245","to seek",47,54],["H3068","the LORD",55,63],["H6635","of hosts",64,72],["H3389","in Jerusalem",73,85],["H2470","and to pray",87,98],["H6440","before",99,105],["H3068","the LORD",106,114]]},"8:23":{"text":"Thus saith the LORD of hosts; In those days it shall come to pass, that ten men shall take hold out of all languages of the nations, even shall take hold of the skirt of him that is a Jew, saying, We will go with you: for we have heard that God is with you.","words":[["H0559","Thus saith",0,10],["H3068","the LORD",11,19],["H6635","of hosts",20,28],["H3117","In those days",30,43],["H6235","it shall come to pass, that ten",44,75],["H0582","men",76,79],["H2388","shall take hold",80,95],["H3956","out of all languages",96,116],["H1471","of the nations",117,131],["H2388","even shall take hold",133,153],["H3671","of the skirt",154,166],["H0376","of him that is a Jew",167,187],["H3064","of him that is a Jew",167,187],["H0559","saying",189,195],["H3212","We will go",197,207],["H8085","with you: for we have heard",208,235],["H0430","that God",236,244]]},"9:1":{"text":"The burden of the word of the LORD in the land of Hadrach, and Damascus shall be the rest thereof: when the eyes of man, as of all the tribes of Israel, shall be toward the LORD.","words":[["H4853","The burden",0,10],["H1697","of the word",11,22],["H3068","of the LORD",23,34],["H0776","in the land",35,46],["H2317","of Hadrach",47,57],["H1834","and Damascus",59,71],["H4496","shall be the rest",72,89],["H5869","thereof: when the eyes",90,112],["H0120","of man",113,119],["H7626","as of all the tribes",121,141],["H3478","of Israel",142,151],["H3068","shall be toward the LORD",153,177]]},"9:2":{"text":"And Hamath also shall border thereby; Tyrus, and Zidon, though it be very wise.","words":[["H2574","And Hamath",0,10],["H1379","also shall border",11,28],["H6865","thereby; Tyrus",29,43],["H6721","and Zidon",45,54],["H3966","though it be very",56,73],["H2449","wise",74,78]]},"9:3":{"text":"And Tyrus did build herself a strong hold, and heaped up silver as the dust, and fine gold as the mire of the streets.","words":[["H6865","And Tyrus",0,9],["H1129","did build",10,19],["H4692","herself a strong hold",20,41],["H6651","and heaped up",43,56],["H3701","silver",57,63],["H6083","as the dust",64,75],["H2742","and fine gold",77,90],["H2916","as the mire",91,102],["H2351","of the streets",103,117]]},"9:4":{"text":"Behold, the Lord will cast her out, and he will smite her power in the sea; and she shall be devoured with fire.","words":[["H0136","Behold, the Lord",0,16],["H3423","will cast her out",17,34],["H5221","and he will smite",36,53],["H2428","her power",54,63],["H3220","in the sea",64,74],["H0398","and she shall be devoured",76,101],["H0784","with fire",102,111]]},"9:5":{"text":"Ashkelon shall see it, and fear; Gaza also shall see it, and be very sorrowful, and Ekron; for her expectation shall be ashamed; and the king shall perish from Gaza, and Ashkelon shall not be inhabited.","words":[["H0831","Ashkelon",0,8],["H7200","shall see",9,18],["H3372","it, and fear",19,31],["H5804","Gaza",33,37],["H3966","also shall see it, and be very",38,68],["H2342","sorrowful",69,78],["H6138","and Ekron",80,89],["H4007","for her expectation",91,110],["H3001","shall be ashamed",111,127],["H4428","and the king",129,141],["H0006","shall perish",142,154],["H5804","from Gaza",155,164],["H0831","and Ashkelon",166,178],["H3427","shall not be inhabited",179,201]]},"9:6":{"text":"And a bastard shall dwell in Ashdod, and I will cut off the pride of the Philistines.","words":[["H4464","And a bastard",0,13],["H3427","shall dwell",14,25],["H0795","in Ashdod",26,35],["H3772","and I will cut off",37,55],["H1347","the pride",56,65],["H6430","of the Philistines",66,84]]},"9:7":{"text":"And I will take away his blood out of his mouth, and his abominations from between his teeth: but he that remaineth, even he, shall be for our God, and he shall be as a governor in Judah, and Ekron as a Jebusite.","words":[["H5493","And I will take away",0,20],["H1818","his blood",21,30],["H6310","out of his mouth",31,47],["H8251","and his abominations",49,69],["H8127","from between his teeth",70,92],["H7604","but he that remaineth",94,115],["H0430","even he, shall be for our God",117,146],["H0441","and he shall be as a governor",148,177],["H3063","in Judah",178,186],["H6138","and Ekron",188,197],["H2983","as a Jebusite",198,211]]},"9:8":{"text":"And I will encamp about mine house because of the army, because of him that passeth by, and because of him that returneth: and no oppressor shall pass through them any more: for now have I seen with mine eyes.","words":[["H2583","And I will encamp",0,17],["H1004","about mine house",18,34],["H4675","because of the army",35,54],["H5674","because of him that passeth by",56,86],["H7725","and because of him that returneth",88,121],["H5065","and no oppressor",123,139],["H5674","shall pass through",140,158],["H7200","them any more: for now have I seen",159,193],["H5869","with mine eyes",194,208]]},"9:9":{"text":"Rejoice greatly, O daughter of Zion; shout, O daughter of Jerusalem: behold, thy King cometh unto thee: he is just, and having salvation; lowly, and riding upon an ass, and upon a colt the foal of an ass.","words":[["H1523","Rejoice",0,7],["H3966","greatly",8,15],["H1323","O daughter",17,27],["H6726","of Zion",28,35],["H7321","shout",37,42],["H1323","O daughter",44,54],["H3389","of Jerusalem",55,67],["H4428","behold, thy King",69,85],["H0935","cometh",86,92],["H6662","unto thee: he is just",93,114],["H3467","and having salvation",116,136],["H6041","lowly",138,143],["H7392","and riding",145,155],["H2543","upon an ass",156,167],["H5895","and upon a colt",169,184],["H1121","the foal",185,193],["H0860","of an ass",194,203]]},"9:10":{"text":"And I will cut off the chariot from Ephraim, and the horse from Jerusalem, and the battle bow shall be cut off: and he shall speak peace unto the heathen: and his dominion shall be from sea even to sea, and from the river even to the ends of the earth.","words":[["H3772","And I will cut off",0,18],["H7393","the chariot",19,30],["H0669","from Ephraim",31,43],["H5483","and the horse",45,58],["H3389","from Jerusalem",59,73],["H4421","and the battle",75,89],["H7198","bow",90,93],["H3772","shall be cut off",94,110],["H1696","and he shall speak",112,130],["H7965","peace",131,136],["H1471","unto the heathen",137,153],["H4915","and his dominion",155,171],["H3220","shall be from sea",172,189],["H3220","even to sea",190,201],["H5104","and from the river",203,221],["H0657","even to the ends",222,238],["H0776","of the earth",239,251]]},"9:11":{"text":"As for thee also, by the blood of thy covenant I have sent forth thy prisoners out of the pit wherein is no water.","words":[["H1818","As for thee also, by the blood",0,30],["H1285","of thy covenant",31,46],["H7971","I have sent forth",47,64],["H0615","thy prisoners",65,78],["H0953","out of the pit",79,93],["H4325","wherein is no water",94,113]]},"9:12":{"text":"Turn you to the strong hold, ye prisoners of hope: even to day do I declare that I will render double unto thee;","words":[["H7725","Turn",0,4],["H1225","you to the strong hold",5,27],["H0615","ye prisoners",29,41],["H8615","of hope",42,49],["H3117","even to day",51,62],["H5046","do I declare",63,75],["H7725","that I will render",76,94],["H4932","double",95,101]]},"9:13":{"text":"When I have bent Judah for me, filled the bow with Ephraim, and raised up thy sons, O Zion, against thy sons, O Greece, and made thee as the sword of a mighty man.","words":[["H1869","When I have bent",0,16],["H3063","Judah",17,22],["H4390","for me, filled",23,37],["H7198","the bow",38,45],["H0669","with Ephraim",46,58],["H5782","and raised up",60,73],["H1121","thy sons",74,82],["H6726","O Zion",84,90],["H1121","against thy sons",92,108],["H3120","O Greece",110,118],["H7760","and made",120,128],["H2719","thee as the sword",129,146],["H1368","of a mighty man",147,162]]},"9:14":{"text":"And the LORD shall be seen over them, and his arrow shall go forth as the lightning: and the Lord GOD shall blow the trumpet, and shall go with whirlwinds of the south.","words":[["H3068","And the LORD",0,12],["H7200","shall be seen",13,26],["H2671","over them, and his arrow",27,51],["H3318","shall go forth",52,66],["H1300","as the lightning",67,83],["H0136","and the Lord",85,97],["H3069","GOD",98,101],["H8628","shall blow",102,112],["H7782","the trumpet",113,124],["H1980","and shall go",126,138],["H5591","with whirlwinds",139,154],["H8486","of the south",155,167]]},"9:15":{"text":"The LORD of hosts shall defend them; and they shall devour, and subdue with sling stones; and they shall drink, and make a noise as through wine; and they shall be filled like bowls, and as the corners of the altar.","words":[["H3068","The LORD",0,8],["H6635","of hosts",9,17],["H1598","shall defend",18,30],["H0398","them; and they shall devour",31,58],["H3533","and subdue",60,70],["H7050","with sling",71,81],["H0068","stones",82,88],["H8354","and they shall drink",90,110],["H1993","and make a noise",112,128],["H3196","as through wine",129,144],["H4390","and they shall be filled",146,170],["H4219","like bowls",171,181],["H2106","and as the corners",183,201],["H4196","of the altar",202,214]]},"9:16":{"text":"And the LORD their God shall save them in that day as the flock of his people: for they shall be as the stones of a crown, lifted up as an ensign upon his land.","words":[["H3068","And the LORD",0,12],["H0430","their God",13,22],["H3467","shall save",23,33],["H3117","them in that day",34,50],["H6629","as the flock",51,63],["H5971","of his people",64,77],["H0068","for they shall be as the stones",79,110],["H5145","of a crown",111,121],["H5264","lifted up as an ensign",123,145],["H0127","upon his land",146,159]]},"9:17":{"text":"For how great is his goodness, and how great is his beauty! corn shall make the young men cheerful, and new wine the maids.","words":[["H2898","For how great is his goodness",0,29],["H3308","and how great is his beauty",31,58],["H1715","corn",60,64],["H0970","shall make the young men",65,89],["H5107","cheerful",90,98],["H8492","and new wine",100,112],["H1330","the maids",113,122]]},"10:1":{"text":"Ask ye of the LORD rain in the time of the latter rain; so the LORD shall make bright clouds, and give them showers of rain, to every one grass in the field.","words":[["H7592","Ask",0,3],["H3068","ye of the LORD",4,18],["H4306","rain",19,23],["H6256","in the time",24,35],["H4456","of the latter rain",36,54],["H3068","so the LORD",56,67],["H6213","shall make",68,78],["H2385","bright clouds",79,92],["H5414","and give",94,102],["H1653","them showers",103,115],["H4306","of rain",116,123],["H0376","to every one",125,137],["H6212","grass",138,143],["H7704","in the field",144,156]]},"10:2":{"text":"For the idols have spoken vanity, and the diviners have seen a lie, and have told false dreams; they comfort in vain: therefore they went their way as a flock, they were troubled, because there was no shepherd.","words":[["H8655","For the idols",0,13],["H1696","have spoken",14,25],["H0205","vanity",26,32],["H7080","and the diviners",34,50],["H2372","have seen",51,60],["H8267","a lie",61,66],["H1696","and have told",68,81],["H7723","false",82,87],["H2472","dreams",88,94],["H5162","they comfort",96,108],["H1892","in vain",109,116],["H5265","therefore they went",118,137],["H6629","their way as a flock",138,158],["H6031","they were troubled",160,178],["H7462","because there was no shepherd",180,209]]},"10:3":{"text":"Mine anger was kindled against the shepherds, and I punished the goats: for the LORD of hosts hath visited his flock the house of Judah, and hath made them as his goodly horse in the battle.","words":[["H0639","Mine anger",0,10],["H2734","was kindled",11,22],["H7462","against the shepherds",23,44],["H6485","and I punished",46,60],["H6260","the goats",61,70],["H3068","for the LORD",72,84],["H6635","of hosts",85,93],["H6485","hath visited",94,106],["H5739","his flock",107,116],["H1004","the house",117,126],["H3063","of Judah",127,135],["H7760","and hath made",137,150],["H1935","them as his goodly",151,169],["H5483","horse",170,175],["H4421","in the battle",176,189]]},"10:4":{"text":"Out of him came forth the corner, out of him the nail, out of him the battle bow, out of him every oppressor together.","words":[["H3318","Out of him came forth",0,21],["H6438","the corner",22,32],["H3489","out of him the nail",34,53],["H4421","out of him the battle",55,76],["H7198","bow",77,80],["H5065","out of him every oppressor",82,108],["H3162","together",109,117]]},"10:5":{"text":"And they shall be as mighty men, which tread down their enemies in the mire of the streets in the battle: and they shall fight, because the LORD is with them, and the riders on horses shall be confounded.","words":[["H1368","And they shall be as mighty",0,27],["H0947","men, which tread down",28,49],["H2916","their enemies in the mire",50,75],["H2351","of the streets",76,90],["H4421","in the battle",91,104],["H3898","and they shall fight",106,126],["H3068","because the LORD",128,144],["H7392","is with them, and the riders",145,173],["H5483","on horses",174,183],["H3001","shall be confounded",184,203]]},"10:6":{"text":"And I will strengthen the house of Judah, and I will save the house of Joseph, and I will bring them again to place them; for I have mercy upon them: and they shall be as though I had not cast them off: for I am the LORD their God, and will hear them.","words":[["H1396","And I will strengthen",0,21],["H1004","the house",22,31],["H3063","of Judah",32,40],["H3467","and I will save",42,57],["H1004","the house",58,67],["H3130","of Joseph",68,77],["H3427","and I will bring them again to place",79,115],["H7355","them; for I have mercy",116,138],["H0834","upon them: and they shall be as though",139,177],["H2186","I had not cast them off",178,201],["H3068","for I am the LORD",203,220],["H0430","their God",221,230],["H6030","and will hear",232,245]]},"10:7":{"text":"And they of Ephraim shall be like a mighty man, and their heart shall rejoice as through wine: yea, their children shall see it, and be glad; their heart shall rejoice in the LORD.","words":[["H0669","And they of Ephraim",0,19],["H1368","shall be like a mighty",20,42],["H3820","man, and their heart",43,63],["H8055","shall rejoice",64,77],["H3196","as through wine",78,93],["H1121","yea, their children",95,114],["H7200","shall see",115,124],["H8055","it, and be glad",125,140],["H3820","their heart",142,153],["H1523","shall rejoice",154,167],["H3068","in the LORD",168,179]]},"10:8":{"text":"I will hiss for them, and gather them; for I have redeemed them: and they shall increase as they have increased.","words":[["H8319","I will hiss",0,11],["H6908","for them, and gather",12,32],["H6299","them; for I have redeemed",33,58],["H7235","them: and they shall increase",59,88],["H7235","as they have increased",89,111]]},"10:9":{"text":"And I will sow them among the people: and they shall remember me in far countries; and they shall live with their children, and turn again.","words":[["H2232","And I will sow",0,14],["H5971","them among the people",15,36],["H2142","and they shall remember",38,61],["H4801","me in far countries",62,81],["H2421","and they shall live",83,102],["H1121","with their children",103,122],["H7725","and turn again",124,138]]},"10:10":{"text":"I will bring them again also out of the land of Egypt, and gather them out of Assyria; and I will bring them into the land of Gilead and Lebanon; and place shall not be found for them.","words":[["H7725","I will bring them again",0,23],["H0776","also out of the land",24,44],["H4714","of Egypt",45,53],["H6908","and gather",55,65],["H0804","them out of Assyria",66,85],["H0935","and I will bring",87,103],["H0776","them into the land",104,122],["H1568","of Gilead",123,132],["H3844","and Lebanon",133,144],["H4672","and place shall not be found",146,174]]},"10:11":{"text":"And he shall pass through the sea with affliction, and shall smite the waves in the sea, and all the deeps of the river shall dry up: and the pride of Assyria shall be brought down, and the sceptre of Egypt shall depart away.","words":[["H5674","And he shall pass through",0,25],["H3220","the sea",26,33],["H6869","with affliction",34,49],["H5221","and shall smite",51,66],["H1530","the waves",67,76],["H3220","in the sea",77,87],["H4688","and all the deeps",89,106],["H2975","of the river",107,119],["H3001","shall dry up",120,132],["H1347","and the pride",134,147],["H0804","of Assyria",148,158],["H3381","shall be brought down",159,180],["H7626","and the sceptre",182,197],["H4714","of Egypt",198,206],["H5493","shall depart away",207,224]]},"10:12":{"text":"And I will strengthen them in the LORD; and they shall walk up and down in his name, saith the LORD.","words":[["H1396","And I will strengthen",0,21],["H3068","them in the LORD",22,38],["H1980","and they shall walk up and down",40,71],["H8034","in his name",72,83],["H5002","saith",85,90],["H3068","the LORD",91,99]]},"11:1":{"text":"Open thy doors, O Lebanon, that the fire may devour thy cedars.","words":[["H6605","Open",0,4],["H1817","thy doors",5,14],["H3844","O Lebanon",16,25],["H0784","that the fire",27,40],["H0398","may devour",41,51],["H0730","thy cedars",52,62]]},"11:2":{"text":"Howl, fir tree; for the cedar is fallen; because the mighty are spoiled: howl, O ye oaks of Bashan; for the forest of the vintage is come down.","words":[["H3213","Howl",0,4],["H1265","fir tree",6,14],["H0730","for the cedar",16,29],["H5307","is fallen",30,39],["H0117","because the mighty",41,59],["H7703","are spoiled",60,71],["H3213","howl",73,77],["H0437","O ye oaks",79,88],["H1316","of Bashan",89,98],["H3293","for the forest",100,114],["H1208","of the vintage",115,129],["H1219","of the vintage",115,129],["H3381","is come down",130,142]]},"11:3":{"text":"There is a voice of the howling of the shepherds; for their glory is spoiled: a voice of the roaring of young lions; for the pride of Jordan is spoiled.","words":[["H6963","There is a voice",0,16],["H3215","of the howling",17,31],["H7462","of the shepherds",32,48],["H0155","for their glory",50,65],["H7703","is spoiled",66,76],["H6963","a voice",78,85],["H7581","of the roaring",86,100],["H3715","of young lions",101,115],["H1347","for the pride",117,130],["H3383","of Jordan",131,140],["H7703","is spoiled",141,151]]},"11:4":{"text":"Thus saith the LORD my God; Feed the flock of the slaughter;","words":[["H0559","Thus saith",0,10],["H3068","the LORD",11,19],["H0430","my God",20,26],["H7462","Feed",28,32],["H6629","the flock",33,42],["H2028","of the slaughter",43,59]]},"11:5":{"text":"Whose possessors slay them, and hold themselves not guilty: and they that sell them say, Blessed be the LORD; for I am rich: and their own shepherds pity them not.","words":[["H7069","Whose possessors",0,16],["H2026","slay",17,21],["H0816","them, and hold themselves not guilty",22,58],["H4376","and they that sell",60,78],["H0559","them say",79,87],["H1288","Blessed",89,96],["H3068","be the LORD",97,108],["H6238","for I am rich",110,123],["H7462","and their own shepherds",125,148],["H2550","pity",149,153]]},"11:6":{"text":"For I will no more pity the inhabitants of the land, saith the LORD: but, lo, I will deliver the men every one into his neighbour's hand, and into the hand of his king: and they shall smite the land, and out of their hand I will not deliver them.","words":[["H2550","For I will no more pity",0,23],["H3427","the inhabitants",24,39],["H0776","of the land",40,51],["H5002","saith",53,58],["H3068","the LORD",59,67],["H4672","but, lo, I will deliver",69,92],["H0120","the men",93,100],["H0376","every one",101,110],["H7453","into his neighbour's",111,131],["H3027","hand",132,136],["H3027","and into the hand",138,155],["H4428","of his king",156,167],["H3807","and they shall smite",169,189],["H0776","the land",190,198],["H3027","and out of their hand",200,221],["H5337","I will not deliver",222,240]]},"11:7":{"text":"And I will feed the flock of slaughter, even you, O poor of the flock. And I took unto me two staves; the one I called Beauty, and the other I called Bands; and I fed the flock.","words":[["H7462","And I will feed",0,15],["H6629","the flock",16,25],["H2028","of slaughter",26,38],["H3651","even you",40,48],["H6041","O poor",50,56],["H6629","of the flock",57,69],["H3947","And I took",71,81],["H8147","unto me two",82,93],["H4731","staves",94,100],["H0259","the one",102,109],["H7121","I called",110,118],["H5278","Beauty",119,125],["H0259","and the other",127,140],["H7121","I called",141,149],["H2254","Bands",150,155],["H7462","and I fed",157,166],["H6629","the flock",167,176]]},"11:8":{"text":"Three shepherds also I cut off in one month; and my soul lothed them, and their soul also abhorred me.","words":[["H7969","Three",0,5],["H7462","shepherds",6,15],["H3582","also I cut off",16,30],["H0259","in one",31,37],["H3391","month",38,43],["H5315","and my soul",45,56],["H7114","lothed",57,63],["H5315","them, and their soul",64,84],["H0973","also abhorred",85,98]]},"11:9":{"text":"Then said I, I will not feed you: that that dieth, let it die; and that that is to be cut off, let it be cut off; and let the rest eat every one the flesh of another.","words":[["H0559","Then said",0,9],["H7462","I, I will not feed",10,28],["H4191","you: that that dieth",29,49],["H4191","let it die",51,61],["H3582","and that that is to be cut off",63,93],["H3582","let it be cut off",95,112],["H7604","and let the rest",114,130],["H0398","eat",131,134],["H0802","every one",135,144],["H1320","the flesh",145,154],["H7468","of another",155,165]]},"11:10":{"text":"And I took my staff, even Beauty, and cut it asunder, that I might break my covenant which I had made with all the people.","words":[["H3947","And I took",0,10],["H4731","my staff",11,19],["H5278","even Beauty",21,32],["H1438","and cut it asunder",34,52],["H6565","that I might break",54,72],["H1285","my covenant",73,84],["H3772","which I had made",85,101],["H5971","with all the people",102,121]]},"11:11":{"text":"And it was broken in that day: and so the poor of the flock that waited upon me knew that it was the word of the LORD.","words":[["H6565","And it was broken",0,17],["H3117","in that day",18,29],["H6041","and so the poor",31,46],["H6629","of the flock",47,59],["H8104","that waited",60,71],["H3045","upon me knew",72,84],["H1697","that it was the word",85,105],["H3068","of the LORD",106,117]]},"11:12":{"text":"And I said unto them, If ye think good, give me my price; and if not, forbear. So they weighed for my price thirty pieces of silver.","words":[["H0559","And I said",0,10],["H5869","unto them, If ye think",11,33],["H2896","good",34,38],["H3051","give",40,44],["H7939","me my price",45,56],["H2308","and if not, forbear",58,77],["H8254","So they weighed",79,94],["H7939","for my price",95,107],["H7970","thirty",108,114],["H3701","pieces of silver",115,131]]},"11:13":{"text":"And the LORD said unto me, Cast it unto the potter: a goodly price that I was prised at of them. And I took the thirty pieces of silver, and cast them to the potter in the house of the LORD.","words":[["H3068","And the LORD",0,12],["H0559","said",13,17],["H7993","unto me, Cast",18,31],["H3335","it unto the potter",32,50],["H0145","a goodly",52,60],["H3366","price",61,66],["H3365","that I was prised at",67,87],["H3947","of them. And I took",88,107],["H7970","the thirty",108,118],["H3701","pieces of silver",119,135],["H7993","and cast",137,145],["H3335","them to the potter",146,164],["H1004","in the house",165,177],["H3068","of the LORD",178,189]]},"11:14":{"text":"Then I cut asunder mine other staff, even Bands, that I might break the brotherhood between Judah and Israel.","words":[["H1438","Then I cut asunder",0,18],["H8145","mine other",19,29],["H4731","staff",30,35],["H2254","even Bands",37,47],["H6565","that I might break",49,67],["H0264","the brotherhood",68,83],["H3063","between Judah",84,97],["H3478","and Israel",98,108]]},"11:15":{"text":"And the LORD said unto me, Take unto thee yet the instruments of a foolish shepherd.","words":[["H3068","And the LORD",0,12],["H0559","said",13,17],["H3947","unto me, Take",18,31],["H3627","unto thee yet the instruments",32,61],["H0196","of a foolish",62,74],["H7462","shepherd",75,83]]},"11:16":{"text":"For, lo, I will raise up a shepherd in the land, which shall not visit those that be cut off, neither shall seek the young one, nor heal that that is broken, nor feed that that standeth still: but he shall eat the flesh of the fat, and tear their claws in pieces.","words":[["H6965","For, lo, I will raise up",0,24],["H7462","a shepherd",25,35],["H0776","in the land",36,47],["H6485","which shall not visit",49,70],["H3582","those that be cut off",71,92],["H1245","neither shall seek",94,112],["H5289","the young one",113,126],["H7495","nor heal",128,136],["H7665","that that is broken",137,156],["H3557","nor feed",158,166],["H5324","that that standeth",167,185],["H0398","still: but he shall eat",186,209],["H1320","the flesh",210,219],["H1277","of the fat",220,230],["H6561","and tear",232,240],["H6541","their claws",241,252],["H6561","in pieces",253,262]]},"11:17":{"text":"Woe to the idol shepherd that leaveth the flock! the sword shall be upon his arm, and upon his right eye: his arm shall be clean dried up, and his right eye shall be utterly darkened.","words":[["H1945","Woe",0,3],["H0457","to the idol",4,15],["H7473","shepherd",16,24],["H5800","that leaveth",25,37],["H6629","the flock",38,47],["H2719","the sword",49,58],["H2220","shall be upon his arm",59,80],["H3225","and upon his right",82,100],["H5869","eye",101,104],["H2220","his arm",106,113],["H3001","shall be clean",114,128],["H3001","dried up",129,137],["H3225","and his right",139,152],["H5869","eye",153,156],["H3543","shall be utterly",157,173],["H3543","darkened",174,182]]},"12:1":{"text":"The burden of the word of the LORD for Israel, saith the LORD, which stretcheth forth the heavens, and layeth the foundation of the earth, and formeth the spirit of man within him.","words":[["H4853","The burden",0,10],["H1697","of the word",11,22],["H3068","of the LORD",23,34],["H3478","for Israel",35,45],["H5002","saith",47,52],["H3068","the LORD",53,61],["H5186","which stretcheth",63,79],["H8064","forth the heavens",80,97],["H3245","and layeth the foundation",99,124],["H0776","of the earth",125,137],["H3335","and formeth",139,150],["H7307","the spirit",151,161],["H0120","of man",162,168],["H7130","within",169,175]]},"12:2":{"text":"Behold, I will make Jerusalem a cup of trembling unto all the people round about, when they shall be in the siege both against Judah and against Jerusalem.","words":[["H7760","Behold, I will make",0,19],["H3389","Jerusalem",20,29],["H5592","a cup",30,35],["H7478","of trembling",36,48],["H5971","unto all the people",49,68],["H5439","round about",69,80],["H4692","when they shall be in the siege",82,113],["H3063","both against Judah",114,132],["H3389","and against Jerusalem",133,154]]},"12:3":{"text":"And in that day will I make Jerusalem a burdensome stone for all people: all that burden themselves with it shall be cut in pieces, though all the people of the earth be gathered together against it.","words":[["H3117","And in that day",0,15],["H7760","will I make",16,27],["H3389","Jerusalem",28,37],["H4614","a burdensome",38,50],["H0068","stone",51,56],["H5971","for all people",57,71],["H6006","all that burden",73,88],["H8295","themselves with it shall be cut in pieces",89,130],["H8295","themselves with it shall be cut in pieces",89,130],["H1471","though all the people",132,153],["H0776","of the earth",154,166],["H0622","be gathered together",167,187]]},"12:4":{"text":"In that day, saith the LORD, I will smite every horse with astonishment, and his rider with madness: and I will open mine eyes upon the house of Judah, and will smite every horse of the people with blindness.","words":[["H3117","In that day",0,11],["H5002","saith",13,18],["H3068","the LORD",19,27],["H5221","I will smite",29,41],["H5483","every horse",42,53],["H8541","with astonishment",54,71],["H7392","and his rider",73,86],["H7697","with madness",87,99],["H6491","and I will open",101,116],["H5869","mine eyes",117,126],["H1004","upon the house",127,141],["H3063","of Judah",142,150],["H5221","and will smite",152,166],["H5483","every horse",167,178],["H5971","of the people",179,192],["H5788","with blindness",193,207]]},"12:5":{"text":"And the governors of Judah shall say in their heart, The inhabitants of Jerusalem shall be my strength in the LORD of hosts their God.","words":[["H0441","And the governors",0,17],["H3063","of Judah",18,26],["H0559","shall say",27,36],["H3820","in their heart",37,51],["H3427","The inhabitants",53,68],["H3389","of Jerusalem",69,81],["H0556","shall be my strength",82,102],["H3068","in the LORD",103,114],["H6635","of hosts",115,123],["H0430","their God",124,133]]},"12:6":{"text":"In that day will I make the governors of Judah like an hearth of fire among the wood, and like a torch of fire in a sheaf; and they shall devour all the people round about, on the right hand and on the left: and Jerusalem shall be inhabited again in her own place, even in Jerusalem.","words":[["H3117","In that day",0,11],["H7760","will I make",12,23],["H0441","the governors",24,37],["H3063","of Judah",38,46],["H3595","like an hearth",47,61],["H0784","of fire",62,69],["H6086","among the wood",70,84],["H3940","and like a torch",86,102],["H0784","of fire",103,110],["H5995","in a sheaf",111,121],["H0398","and they shall devour",123,144],["H5971","all the people",145,159],["H5439","round about",160,171],["H3225","on the right hand",173,190],["H8040","and on the left",191,206],["H3389","and Jerusalem",208,221],["H3427","shall be inhabited",222,240],["H3389","again in her own place, even in Jerusalem",241,282]]},"12:7":{"text":"The LORD also shall save the tents of Judah first, that the glory of the house of David and the glory of the inhabitants of Jerusalem do not magnify themselves against Judah.","words":[["H3068","The LORD",0,8],["H3467","also shall save",9,24],["H0168","the tents",25,34],["H3063","of Judah",35,43],["H7223","first",44,49],["H8597","that the glory",51,65],["H1004","of the house",66,78],["H1732","of David",79,87],["H8597","and the glory",88,101],["H3427","of the inhabitants",102,120],["H3389","of Jerusalem",121,133],["H1431","do not magnify",134,148],["H3063","themselves against Judah",149,173]]},"12:8":{"text":"In that day shall the LORD defend the inhabitants of Jerusalem; and he that is feeble among them at that day shall be as David; and the house of David shall be as God, as the angel of the LORD before them.","words":[["H3117","In that day",0,11],["H3068","shall the LORD",12,26],["H1598","defend",27,33],["H3427","the inhabitants",34,49],["H3389","of Jerusalem",50,62],["H3782","and he that is feeble",64,85],["H3117","among them at that day",86,108],["H1732","shall be as David",109,126],["H1004","and the house",128,141],["H1732","of David",142,150],["H0430","shall be as God",151,166],["H4397","as the angel",168,180],["H3068","of the LORD",181,192],["H6440","before",193,199]]},"12:9":{"text":"And it shall come to pass in that day, that I will seek to destroy all the nations that come against Jerusalem.","words":[["H3117","And it shall come to pass in that day",0,37],["H1245","that I will seek",39,55],["H8045","to destroy",56,66],["H1471","all the nations",67,82],["H0935","that come",83,92],["H3389","against Jerusalem",93,110]]},"12:10":{"text":"And I will pour upon the house of David, and upon the inhabitants of Jerusalem, the spirit of grace and of supplications: and they shall look upon me whom they have pierced, and they shall mourn for him, as one mourneth for his only son, and shall be in bitterness for him, as one that is in bitterness for his firstborn.","words":[["H8210","And I will pour",0,15],["H1004","upon the house",16,30],["H1732","of David",31,39],["H3427","and upon the inhabitants",41,65],["H3389","of Jerusalem",66,78],["H7307","the spirit",80,90],["H2580","of grace",91,99],["H8469","and of supplications",100,120],["H5027","and they shall look",122,141],["H1856","upon me whom they have pierced",142,172],["H4553","and they shall mourn",174,194],["H5594","for him, as one mourneth",195,219],["H3173","for his only",220,232],["H4843","son, and shall be in bitterness",233,264],["H4843","for him, as one that is in bitterness",265,302],["H1060","for his firstborn",303,320]]},"12:11":{"text":"In that day shall there be a great mourning in Jerusalem, as the mourning of Hadadrimmon in the valley of Megiddon.","words":[["H3117","In that day",0,11],["H1431","shall there be a great",12,34],["H4553","mourning",35,43],["H3389","in Jerusalem",44,56],["H4553","as the mourning",58,73],["H1910","of Hadadrimmon",74,88],["H1237","in the valley",89,102],["H4023","of Megiddon",103,114]]},"12:12":{"text":"And the land shall mourn, every family apart; the family of the house of David apart, and their wives apart; the family of the house of Nathan apart, and their wives apart;","words":[["H0776","And the land",0,12],["H5594","shall mourn",13,24],["H4940","every",26,31],["H4940","family",32,38],["H0905","apart",39,44],["H4940","the family",46,56],["H1004","of the house",57,69],["H1732","of David",70,78],["H0802","apart, and their wives",79,101],["H4940","apart; the family",102,119],["H1004","of the house",120,132],["H5416","of Nathan",133,142],["H0802","apart, and their wives",143,165]]},"12:13":{"text":"The family of the house of Levi apart, and their wives apart; the family of Shimei apart, and their wives apart;","words":[["H4940","The family",0,10],["H1004","of the house",11,23],["H3878","of Levi",24,31],["H0802","apart, and their wives",32,54],["H4940","apart; the family",55,72],["H8097","of Shimei",73,82],["H0802","apart, and their wives",83,105]]},"12:14":{"text":"All the families that remain, every family apart, and their wives apart.","words":[["H4940","All the families",0,16],["H7604","that remain",17,28],["H4940","every family",30,42],["H0802","apart, and their wives",43,65]]},"13:1":{"text":"In that day there shall be a fountain opened to the house of David and to the inhabitants of Jerusalem for sin and for uncleanness.","words":[["H3117","In that day",0,11],["H4726","there shall be a fountain",12,37],["H6605","opened",38,44],["H1004","to the house",45,57],["H1732","of David",58,66],["H3427","and to the inhabitants",67,89],["H3389","of Jerusalem",90,102],["H2403","for sin",103,110],["H5079","and for uncleanness",111,130]]},"13:2":{"text":"And it shall come to pass in that day, saith the LORD of hosts, that I will cut off the names of the idols out of the land, and they shall no more be remembered: and also I will cause the prophets and the unclean spirit to pass out of the land.","words":[["H3117","And it shall come to pass in that day",0,37],["H5002","saith",39,44],["H3068","the LORD",45,53],["H6635","of hosts",54,62],["H3772","that I will cut off",64,83],["H8034","the names",84,93],["H6091","of the idols",94,106],["H0776","out of the land",107,122],["H2142","and they shall no more be remembered",124,160],["H5030","and also I will cause the prophets",162,196],["H2932","and the unclean",197,212],["H7307","spirit",213,219],["H5674","to pass",220,227],["H0776","out of the land",228,243]]},"13:3":{"text":"And it shall come to pass, that when any shall yet prophesy, then his father and his mother that begat him shall say unto him, Thou shalt not live; for thou speakest lies in the name of the LORD: and his father and his mother that begat him shall thrust him through when he prophesieth.","words":[["H0376","And it shall come to pass, that when any",0,40],["H5012","shall yet prophesy",41,59],["H0001","then his father",61,76],["H0517","and his mother",77,91],["H3205","that begat",92,102],["H0559","him shall say",103,116],["H2421","unto him, Thou shalt not live",117,146],["H1696","for thou speakest",148,165],["H8267","lies",166,170],["H8034","in the name",171,182],["H3068","of the LORD",183,194],["H0001","and his father",196,210],["H0517","and his mother",211,225],["H3205","that begat",226,236],["H1856","him shall thrust",237,253],["H5012","him through when he prophesieth",254,285]]},"13:4":{"text":"And it shall come to pass in that day, that the prophets shall be ashamed every one of his vision, when he hath prophesied; neither shall they wear a rough garment to deceive:","words":[["H3117","And it shall come to pass in that day",0,37],["H5030","that the prophets",39,56],["H0954","shall be ashamed",57,73],["H0376","every one",74,83],["H2384","of his vision",84,97],["H5012","when he hath prophesied",99,122],["H3847","neither shall they wear",124,147],["H8181","a rough",148,155],["H0155","garment",156,163],["H3584","to deceive",164,174]]},"13:5":{"text":"But he shall say, I am no prophet, I am an husbandman; for man taught me to keep cattle from my youth.","words":[["H0559","But he shall say",0,16],["H5030","I am no prophet",18,33],["H0376","I am an husbandman",35,53],["H5647","I am an husbandman",35,53],["H0127","I am an husbandman",35,53],["H0120","for man",55,62],["H7069","taught me to keep cattle",63,87],["H5271","from my youth",88,101]]},"13:6":{"text":"And one shall say unto him, What are these wounds in thine hands? Then he shall answer, Those with which I was wounded in the house of my friends.","words":[["H0559","And one shall say",0,17],["H4347","unto him, What are these wounds",18,49],["H3027","in thine hands",50,64],["H0559","Then he shall answer",66,86],["H5221","Those with which I was wounded",88,118],["H1004","in the house",119,131],["H0157","of my friends",132,145]]},"13:7":{"text":"Awake, O sword, against my shepherd, and against the man that is my fellow, saith the LORD of hosts: smite the shepherd, and the sheep shall be scattered: and I will turn mine hand upon the little ones.","words":[["H5782","Awake",0,5],["H2719","O sword",7,14],["H7462","against my shepherd",16,35],["H1397","and against the man",37,56],["H5997","that is my fellow",57,74],["H5002","saith",76,81],["H3068","the LORD",82,90],["H6635","of hosts",91,99],["H5221","smite",101,106],["H7462","the shepherd",107,119],["H6629","and the sheep",121,134],["H6327","shall be scattered",135,153],["H7725","and I will turn",155,170],["H3027","mine hand",171,180],["H6819","upon the little ones",181,201]]},"13:8":{"text":"And it shall come to pass, that in all the land, saith the LORD, two parts therein shall be cut off and die; but the third shall be left therein.","words":[["H0776","And it shall come to pass, that in all the land",0,47],["H5002","saith",49,54],["H3068","the LORD",55,63],["H8147","two",65,68],["H6310","parts",69,74],["H3772","therein shall be cut off",75,99],["H1478","and die",100,107],["H7992","but the third",109,122],["H3498","shall be left",123,136]]},"13:9":{"text":"And I will bring the third part through the fire, and will refine them as silver is refined, and will try them as gold is tried: they shall call on my name, and I will hear them: I will say, It is my people: and they shall say, The LORD is my God.","words":[["H0935","And I will bring",0,16],["H7992","the third part",17,31],["H0784","through the fire",32,48],["H6884","and will refine",50,65],["H3701","them as silver",66,80],["H6884","is refined",81,91],["H0974","and will try",93,105],["H2091","them as gold",106,118],["H0974","is tried",119,127],["H7121","they shall call",129,144],["H8034","on my name",145,155],["H6030","and I will hear",157,172],["H0559","them: I will say",173,189],["H5971","It is my people",191,206],["H0559","and they shall say",208,226],["H3068","The LORD",228,236],["H0430","is my God",237,246]]},"14:1":{"text":"Behold, the day of the LORD cometh, and thy spoil shall be divided in the midst of thee.","words":[["H3117","Behold, the day",0,15],["H3068","of the LORD",16,27],["H0935","cometh",28,34],["H7998","and thy spoil",36,49],["H2505","shall be divided",50,66],["H7130","in the midst",67,79]]},"14:2":{"text":"For I will gather all nations against Jerusalem to battle; and the city shall be taken, and the houses rifled, and the women ravished; and half of the city shall go forth into captivity, and the residue of the people shall not be cut off from the city.","words":[["H0622","For I will gather",0,17],["H1471","all nations",18,29],["H3389","against Jerusalem",30,47],["H4421","to battle",48,57],["H5892","and the city",59,71],["H3920","shall be taken",72,86],["H1004","and the houses",88,102],["H8155","rifled",103,109],["H0802","and the women",111,124],["H7901","ravished",125,133],["H7693","ravished",125,133],["H2677","and half",135,143],["H5892","of the city",144,155],["H3318","shall go forth",156,170],["H1473","into captivity",171,185],["H3499","and the residue",187,202],["H5971","of the people",203,216],["H3772","shall not be cut off",217,237],["H5892","from the city",238,251]]},"14:3":{"text":"Then shall the LORD go forth, and fight against those nations, as when he fought in the day of battle.","words":[["H3068","Then shall the LORD",0,19],["H3318","go forth",20,28],["H3898","and fight",30,39],["H1471","against those nations",40,61],["H3117","as when",63,70],["H3898","he fought",71,80],["H3117","in the day",81,91],["H7128","of battle",92,101]]},"14:4":{"text":"And his feet shall stand in that day upon the mount of Olives, which is before Jerusalem on the east, and the mount of Olives shall cleave in the midst thereof toward the east and toward the west, and there shall be a very great valley; and half of the mountain shall remove toward the north, and half of it toward the south.","words":[["H7272","And his feet",0,12],["H5975","shall stand",13,24],["H3117","in that day",25,36],["H2022","upon the mount",37,51],["H2132","of Olives",52,61],["H6440","which is before",63,78],["H3389","Jerusalem",79,88],["H6924","on the east",89,100],["H2022","and the mount",102,115],["H2132","of Olives",116,125],["H1234","shall cleave",126,138],["H2677","in the midst",139,151],["H4217","thereof toward the east",152,175],["H3220","and toward the west",176,195],["H3966","and there shall be a very",197,222],["H1419","great",223,228],["H1516","valley",229,235],["H2677","and half",237,245],["H2022","of the mountain",246,261],["H4185","shall remove",262,274],["H6828","toward the north",275,291],["H2677","and half",293,301],["H5045","of it toward the south",302,324]]},"14:5":{"text":"And ye shall flee to the valley of the mountains; for the valley of the mountains shall reach unto Azal: yea, ye shall flee, like as ye fled from before the earthquake in the days of Uzziah king of Judah: and the LORD my God shall come, and all the saints with thee.","words":[["H5127","And ye shall flee",0,17],["H1516","to the valley",18,31],["H2022","of the mountains",32,48],["H1516","for the valley",50,64],["H2022","of the mountains",65,81],["H5060","shall reach",82,93],["H0682","unto Azal",94,103],["H5127","yea, ye shall flee",105,123],["H5127","like as ye fled",125,140],["H6440","from before",141,152],["H7494","the earthquake",153,167],["H3117","in the days",168,179],["H5818","of Uzziah",180,189],["H4428","king",190,194],["H3063","of Judah",195,203],["H3068","and the LORD",205,217],["H0430","my God",218,224],["H0935","shall come",225,235],["H6918","and all the saints",237,255]]},"14:6":{"text":"And it shall come to pass in that day, that the light shall not be clear, nor dark:","words":[["H3117","And it shall come to pass in that day",0,37],["H0216","that the light",39,53],["H3368","shall not be clear",54,72],["H7087","nor dark",74,82],["H7087","nor dark",74,82]]},"14:7":{"text":"But it shall be one day which shall be known to the LORD, not day, nor night: but it shall come to pass, that at evening time it shall be light.","words":[["H0259","But it shall be one",0,19],["H3117","day",20,23],["H3045","which shall be known",24,44],["H3068","to the LORD",45,56],["H3117","not day",58,65],["H3915","nor night",67,76],["H6153","but it shall come to pass, that at evening",78,120],["H6256","time",121,125],["H0216","it shall be light",126,143]]},"14:8":{"text":"And it shall be in that day, that living waters shall go out from Jerusalem; half of them toward the former sea, and half of them toward the hinder sea: in summer and in winter shall it be.","words":[["H3117","And it shall be in that day",0,27],["H2416","that living",29,40],["H4325","waters",41,47],["H3318","shall go out",48,60],["H3389","from Jerusalem",61,75],["H2677","half",77,81],["H6931","of them toward the former",82,107],["H3220","sea",108,111],["H2677","and half",113,121],["H0314","of them toward the hinder",122,147],["H3220","sea",148,151],["H7019","in summer",153,162],["H2779","and in winter",163,176]]},"14:9":{"text":"And the LORD shall be king over all the earth: in that day shall there be one LORD, and his name one.","words":[["H3068","And the LORD",0,12],["H4428","shall be king",13,26],["H0776","over all the earth",27,45],["H3117","in that day",47,58],["H0259","shall there be one",59,77],["H3068","LORD",78,82],["H8034","and his name",84,96],["H0259","one",97,100]]},"14:10":{"text":"All the land shall be turned as a plain from Geba to Rimmon south of Jerusalem: and it shall be lifted up, and inhabited in her place, from Benjamin's gate unto the place of the first gate, unto the corner gate, and from the tower of Hananeel unto the king's winepresses.","words":[["H0776","All the land",0,12],["H5437","shall be turned",13,28],["H6160","as a plain",29,39],["H1387","from Geba",40,49],["H7417","to Rimmon",50,59],["H5045","south",60,65],["H3389","of Jerusalem",66,78],["H7213","and it shall be lifted up",80,105],["H3427","and inhabited",107,120],["H1144","in her place, from Benjamin's",121,150],["H8179","gate",151,155],["H4725","unto the place",156,170],["H7223","of the first",171,183],["H8179","gate",184,188],["H6434","unto the corner",190,205],["H8179","gate",206,210],["H4026","and from the tower",212,230],["H2606","of Hananeel",231,242],["H4428","unto the king's",243,258],["H3342","winepresses",259,270]]},"14:11":{"text":"And men shall dwell in it, and there shall be no more utter destruction; but Jerusalem shall be safely inhabited.","words":[["H3427","And men shall dwell",0,19],["H2764","in it, and there shall be no more utter destruction",20,71],["H3389","but Jerusalem",73,86],["H0983","shall be safely",87,102],["H3427","inhabited",103,112]]},"14:12":{"text":"And this shall be the plague wherewith the LORD will smite all the people that have fought against Jerusalem; Their flesh shall consume away while they stand upon their feet, and their eyes shall consume away in their holes, and their tongue shall consume away in their mouth.","words":[["H4046","And this shall be the plague",0,28],["H3068","wherewith the LORD",29,47],["H5062","will smite",48,58],["H5971","all the people",59,73],["H6633","that have fought",74,90],["H3389","against Jerusalem",91,108],["H1320","Their flesh",110,121],["H4743","shall consume away",122,140],["H5975","while they stand",141,157],["H7272","upon their feet",158,173],["H5869","and their eyes",175,189],["H4743","shall consume away",190,208],["H2356","in their holes",209,223],["H3956","and their tongue",225,241],["H4743","shall consume away",242,260],["H6310","in their mouth",261,275]]},"14:13":{"text":"And it shall come to pass in that day, that a great tumult from the LORD shall be among them; and they shall lay hold every one on the hand of his neighbour, and his hand shall rise up against the hand of his neighbour.","words":[["H3117","And it shall come to pass in that day",0,37],["H7227","that a great",39,51],["H4103","tumult",52,58],["H3068","from the LORD",59,72],["H2388","shall be among them; and they shall lay hold",73,117],["H0376","every one",118,127],["H3027","on the hand",128,139],["H7453","of his neighbour",140,156],["H3027","and his hand",158,170],["H5927","shall rise up",171,184],["H3027","against the hand",185,201],["H7453","of his neighbour",202,218]]},"14:14":{"text":"And Judah also shall fight at Jerusalem; and the wealth of all the heathen round about shall be gathered together, gold, and silver, and apparel, in great abundance.","words":[["H3063","And Judah",0,9],["H3898","also shall fight",10,26],["H3389","at Jerusalem",27,39],["H2428","and the wealth",41,55],["H1471","of all the heathen",56,74],["H5439","round about",75,86],["H0622","shall be gathered together",87,113],["H2091","gold",115,119],["H3701","and silver",121,131],["H0899","and apparel",133,144],["H3966","in great",146,154],["H7230","abundance",155,164]]},"14:15":{"text":"And so shall be the plague of the horse, of the mule, of the camel, and of the ass, and of all the beasts that shall be in these tents, as this plague.","words":[["H4046","And so shall be the plague",0,26],["H5483","of the horse",27,39],["H6505","of the mule",41,52],["H1581","of the camel",54,66],["H2543","and of the ass",68,82],["H0929","and of all the beasts",84,105],["H1992","that shall be in these",106,128],["H4264","tents",129,134],["H4046","as this plague",136,150]]},"14:16":{"text":"And it shall come to pass, that every one that is left of all the nations which came against Jerusalem shall even go up from year to year to worship the King, the LORD of hosts, and to keep the feast of tabernacles.","words":[["H3498","And it shall come to pass, that every one that is left",0,54],["H1471","of all the nations",55,73],["H0935","which came",74,84],["H3389","against Jerusalem",85,102],["H5927","shall even go up",103,119],["H1767","from",120,124],["H8141","year",125,129],["H8141","to year",130,137],["H7812","to worship",138,148],["H4428","the King",149,157],["H3068","the LORD",159,167],["H6635","of hosts",168,176],["H2287","and to keep",178,189],["H2282","the feast",190,199],["H5521","of tabernacles",200,214]]},"14:17":{"text":"And it shall be, that whoso will not come up of all the families of the earth unto Jerusalem to worship the King, the LORD of hosts, even upon them shall be no rain.","words":[["H5927","And it shall be, that whoso will not come up",0,44],["H4940","of all the families",45,64],["H0776","of the earth",65,77],["H3389","unto Jerusalem",78,92],["H7812","to worship",93,103],["H4428","the King",104,112],["H3068","the LORD",114,122],["H6635","of hosts",123,131],["H1653","even upon them shall be no rain",133,164]]},"14:18":{"text":"And if the family of Egypt go not up, and come not, that have no rain; there shall be the plague, wherewith the LORD will smite the heathen that come not up to keep the feast of tabernacles.","words":[["H4940","And if the family",0,17],["H4714","of Egypt",18,26],["H5927","go not up",27,36],["H0935","and come",38,46],["H4046","not, that have no rain; there shall be the plague",47,96],["H3068","wherewith the LORD",98,116],["H5062","will smite",117,127],["H1471","the heathen",128,139],["H5927","that come not up",140,156],["H2287","to keep",157,164],["H2282","the feast",165,174],["H5521","of tabernacles",175,189]]},"14:19":{"text":"This shall be the punishment of Egypt, and the punishment of all nations that come not up to keep the feast of tabernacles.","words":[["H2403","This shall be the punishment",0,28],["H4714","of Egypt",29,37],["H2403","and the punishment",39,57],["H1471","of all nations",58,72],["H5927","that come not up",73,89],["H2287","to keep",90,97],["H2282","the feast",98,107],["H5521","of tabernacles",108,122]]},"14:20":{"text":"In that day shall there be upon the bells of the horses, HOLINESS UNTO THE LORD; and the pots in the LORD'S house shall be like the bowls before the altar.","words":[["H3117","In that day",0,11],["H4698","shall there be upon the bells",12,41],["H5483","of the horses",42,55],["H6944","HOLINESS",57,65],["H3068","UNTO THE LORD",66,79],["H5518","and the pots",81,93],["H3068","in the LORD'S",94,107],["H1004","house",108,113],["H4219","shall be like the bowls",114,137],["H6440","before",138,144],["H4196","the altar",145,154]]},"14:21":{"text":"Yea, every pot in Jerusalem and in Judah shall be holiness unto the LORD of hosts: and all they that sacrifice shall come and take of them, and seethe therein: and in that day there shall be no more the Canaanite in the house of the LORD of hosts.","words":[["H5518","Yea, every pot",0,14],["H3389","in Jerusalem",15,27],["H3063","and in Judah",28,40],["H6944","shall be holiness",41,58],["H3068","unto the LORD",59,72],["H6635","of hosts",73,81],["H2076","and all they that sacrifice",83,110],["H0935","shall come",111,121],["H3947","and take",122,130],["H1310","of them, and seethe",131,150],["H3117","therein: and in that day",151,175],["H3669","there shall be no more the Canaanite",176,212],["H1004","in the house",213,225],["H3068","of the LORD",226,237],["H6635","of hosts",238,246]]}}};
